function examRequestTimeout(timeoutMs: number = 60000) {
  return (req: Request, res: Response, next: NextFunction) => {
    let finished = false;

    const timer = setTimeout(() => {
      if (!res.headersSent && !finished) {
        console.error(`[Timeout] ${req.method} ${req.originalUrl} exceeded ${timeoutMs}ms`);
        res.status(504).json({ error: "Request timed out", timeout: timeoutMs });
      }
    }, timeoutMs);

    res.on("finish", () => {
      finished = true;
      clearTimeout(timer);
    });

    res.on("close", () => {
      finished = true;
      clearTimeout(timer);
    });

    next();
  };
}

function parseStoragePath(path: string): { bucketName: string; objectName: string } {
  if (!path.startsWith("/")) path = `/${path}`;
  const parts = path.split("/");
  if (parts.length < 3) throw new Error("Invalid storage path");
  return { bucketName: parts[1], objectName: parts.slice(2).join("/") };
}

function snakeToCamel(obj: any): any {
  if (Array.isArray(obj)) return obj.map(snakeToCamel);
  if (obj === null || typeof obj !== "object") return obj;
  const result: any = {};
  for (const [key, value] of Object.entries(obj)) {
    const camelKey = key.replace(/_([a-z])/g, (_, c) => c.toUpperCase());
    result[camelKey] = value;
  }
  return result;
}

