  app.put("/api/admin/roles/:userId", async (req, res) => {
    try {
      const admin = await requireAdmin(req, res);
      if (!admin) return;
      const adminRole = admin.adminRole || (admin as any).admin_role || "super_admin";
      if (adminRole !== "super_admin") {
        return res.status(403).json({ error: "Only super admins can manage roles" });
      }
      const { role, confirmationToken } = req.body;
      const validRoles: AdminRole[] = ["super_admin", "content_admin", "support_admin", "ops_viewer", "analytics_viewer"];
      if (!role || !validRoles.includes(role)) {
        return res.status(400).json({ error: `Invalid role. Must be one of: ${validRoles.join(", ")}` });
      }

      if (!confirmationToken) {
        const token = issueConfirmationToken(admin.id, "user_management", { userId: req.params.userId, role });
        return res.status(428).json({
          error: "Destructive action requires confirmation",
          confirmationToken: token,
          action: "user_management",
          message: "Re-submit with the provided confirmationToken to proceed",
        });
      }
      const validation = validateConfirmationToken(confirmationToken, admin.id, "user_management");
      if (!validation.valid) {
        return res.status(403).json({ error: "Invalid or expired confirmation token" });
      }

      const targetUser = await storage.getUser(req.params.userId);
      if (!targetUser || targetUser.tier !== "admin") {
        return res.status(404).json({ error: "Admin user not found" });
      }
      const beforeRole = targetUser.adminRole || (targetUser as any).admin_role || "super_admin";
      await pool.query("UPDATE users SET admin_role = $1 WHERE id = $2", [role, req.params.userId]);
      await logOperatorAction({
        req, actor: admin, action: "admin_role_changed", actionCategory: "user_management",
        entityType: "user", entityId: req.params.userId,
        targetType: "admin_role", targetId: req.params.userId,
        reason: req.body.reason || null,
        confirmationRequired: true,
        beforeState: { role: beforeRole }, afterState: { role },
      });
      res.json({ success: true, userId: req.params.userId, role });
    } catch (e: any) {
      res.status(500).json({ error: e.message });
    }
  });

  let _alliedHealthTotalCache: number | null = null;
  function getAlliedHealthTotal(): number {
    if (_alliedHealthTotalCache !== null) return _alliedHealthTotalCache;
    try {
      const manifestPath = nodePath.resolve(process.cwd(), "client/src/data/career-questions/question-manifest.json");
      const questionManifest = JSON.parse(fs.readFileSync(manifestPath, "utf-8"));
      _alliedHealthTotalCache = Object.values(questionManifest.static.alliedHealth as Record<string, { total: number }>).reduce(
        (sum: number, entry: { total: number }) => sum + entry.total, 0
      );
    } catch (e) {
      console.error("[AlliedHealth] Failed to load question manifest:", e);
      _alliedHealthTotalCache = 0;
    }
    return _alliedHealthTotalCache;
  }

  let heroStatsCache: { data: any; timestamp: number } | null = null;
  const HERO_CACHE_TTL = 10 * 60 * 1000;

  app.get("/api/hero-stats", async (_req, res) => {
    try {
      if (heroStatsCache && Date.now() - heroStatsCache.timestamp < HERO_CACHE_TTL) {
        return res.json(heroStatsCache.data);
      }

      const { tierCounts } = await import("@shared/tier-counts");
      const alliedHealthTotal = getAlliedHealthTotal();

      const dbResult = await pool.query(`
        SELECT
          COALESCE(SUM(CASE WHEN tier = 'rpn' THEN 1 ELSE 0 END), 0) AS rpn_db,
          COALESCE(SUM(CASE WHEN tier = 'rn' THEN 1 ELSE 0 END), 0) AS rn_db,
          COALESCE(SUM(CASE WHEN tier = 'np' THEN 1 ELSE 0 END), 0) AS np_db,
          COALESCE(SUM(CASE WHEN tier = 'free' OR tier IS NULL THEN 1 ELSE 0 END), 0) AS free_db,
          COUNT(*) AS total_db
        FROM content_items WHERE status = 'published'
      `);

      const storeResult = await pool.query(`
        SELECT
          COALESCE(SUM(question_count), 0) AS store_questions,
          COUNT(*) AS store_products
        FROM digital_products WHERE is_active = true
      `);

      const examQResult = await pool.query(`
        SELECT
          COALESCE(SUM(CASE WHEN tier = 'rpn' THEN 1 ELSE 0 END), 0) AS rpn_eq,
          COALESCE(SUM(CASE WHEN tier = 'rn' THEN 1 ELSE 0 END), 0) AS rn_eq,
          COALESCE(SUM(CASE WHEN tier = 'np' THEN 1 ELSE 0 END), 0) AS np_eq,
          COUNT(*) AS total_eq
        FROM exam_questions WHERE status = 'published'
      `);

      const db = dbResult.rows[0] || { rpn_db: 0, rn_db: 0, np_db: 0, free_db: 0, total_db: 0 };
      const store = storeResult.rows[0] || { store_questions: 0, store_products: 0 };
      const eq = examQResult.rows[0] || { rpn_eq: 0, rn_eq: 0, np_eq: 0, total_eq: 0 };

      const rpnLessons = tierCounts.rpn + Number(db.rpn_db);
      const rnLessons = tierCounts.rn + Number(db.rn_db);
      const npLessons = tierCounts.np + Number(db.np_db);
      const freeLessons = tierCounts.free + Number(db.free_db);
      const totalLessons = rpnLessons + rnLessons + npLessons + freeLessons;
      const paidLessons = rpnLessons + rnLessons + npLessons;
      const storeQuestionCount = Number(store.store_questions);
      const storeProductCount = Number(store.store_products);
      const examQuestionCount = Number(eq.total_eq);
      const totalQuestions = tierCounts.questionCount + storeQuestionCount + examQuestionCount + alliedHealthTotal;

      const stats = {
        rpnLessons,
        rnLessons,
        npLessons,
        freeLessons,
        totalLessons,
        paidLessons,
        questionCount: totalQuestions,
        storeQuestionCount,
        storeProductCount,
        lastUpdatedISO: new Date().toISOString(),
        breakdown: {
          rpnStatic: tierCounts.rpn,
          rnStatic: tierCounts.rn,
          npStatic: tierCounts.np,
          freeStatic: tierCounts.free,
          rpnDb: Number(db.rpn_db),
          rnDb: Number(db.rn_db),
          npDb: Number(db.np_db),
          freeDb: Number(db.free_db),
          rpnExamQ: Number(eq.rpn_eq),
          rnExamQ: Number(eq.rn_eq),
          npExamQ: Number(eq.np_eq),
          totalExamQ: examQuestionCount,
          alliedHealthStatic: alliedHealthTotal,
        },
      };

      heroStatsCache = { data: stats, timestamp: Date.now() };
      res.json(stats);
    } catch (error: any) {
      console.error("Hero stats error:", error);
      res.status(500).json({ error: "Failed to compute stats" });
    }
  });

  let tierQuestionCountsCache: { data: any; timestamp: number } | null = null;
  const TIER_Q_CACHE_TTL = 5 * 60 * 1000;

  app.get("/api/tier-question-counts", async (_req, res) => {
    try {
      if (tierQuestionCountsCache && Date.now() - tierQuestionCountsCache.timestamp < TIER_Q_CACHE_TTL) {
        return res.json(tierQuestionCountsCache.data);
      }

      const result = await pool.query(`
        SELECT
          tier,
          COUNT(*)::int AS count
        FROM exam_questions
        WHERE status = 'published'
        GROUP BY tier
        ORDER BY tier
      `);

      const counts: Record<string, number> = {};
      let total = 0;
      for (const row of result.rows) {
        counts[row.tier] = row.count;
        total += row.count;
      }

      const data = {
        rpn: counts.rpn || 0,
        rn: counts.rn || 0,
        np: counts.np || 0,
        free: counts.free || 0,
        total,
        counts,
        computedAt: new Date().toISOString(),
      };

      tierQuestionCountsCache = { data, timestamp: Date.now() };
      res.json(data);
    } catch (error: any) {
      console.error("Tier question counts error:", error);
      res.status(500).json({ error: "Failed to compute tier question counts" });
    }
  });

