  const PLATFORM_PROOF_CACHE_TTL = 15 * 60 * 1000;

  app.get("/api/public/platform-proof", async (_req, res) => {
    try {
      if (platformProofCache && Date.now() - platformProofCache.timestamp < PLATFORM_PROOF_CACHE_TTL) {
        return res.json(platformProofCache.data);
      }

      const { tierCounts } = await import("@shared/tier-counts");
      const ppAlliedHealthTotal = getAlliedHealthTotal();

      const [dbLessons, storeData, examQ, flashcardCount, deckCount] = await Promise.all([
        pool.query(`
          SELECT
            COALESCE(SUM(CASE WHEN tier = 'rpn' THEN 1 ELSE 0 END), 0) AS rpn_db,
            COALESCE(SUM(CASE WHEN tier = 'rn' THEN 1 ELSE 0 END), 0) AS rn_db,
            COALESCE(SUM(CASE WHEN tier = 'np' THEN 1 ELSE 0 END), 0) AS np_db,
            COALESCE(SUM(CASE WHEN tier = 'free' OR tier IS NULL THEN 1 ELSE 0 END), 0) AS free_db,
            COUNT(*) AS total_db
          FROM content_items WHERE status = 'published'
        `),
        pool.query(`
          SELECT COALESCE(SUM(question_count), 0) AS store_questions FROM digital_products WHERE is_active = true
        `),
        pool.query(`
          SELECT
            COALESCE(SUM(CASE WHEN tier = 'rpn' THEN 1 ELSE 0 END), 0) AS rpn_eq,
            COALESCE(SUM(CASE WHEN tier = 'rn' THEN 1 ELSE 0 END), 0) AS rn_eq,
            COALESCE(SUM(CASE WHEN tier = 'np' THEN 1 ELSE 0 END), 0) AS np_eq,
            COUNT(*) AS total_eq
          FROM exam_questions WHERE status = 'published'
        `),
        pool.query(`SELECT COUNT(*)::int AS count FROM flashcard_bank`).catch(() => ({ rows: [{ count: 0 }] })),
        pool.query(`SELECT COUNT(*)::int AS count FROM flashcard_decks`).catch(() => ({ rows: [{ count: 0 }] })),
      ]);

      const db = dbLessons.rows[0] || {};
      const store = storeData.rows[0] || {};
      const eq = examQ.rows[0] || {};

      const totalLessons = (tierCounts.rpn + Number(db.rpn_db)) +
        (tierCounts.rn + Number(db.rn_db)) +
        (tierCounts.np + Number(db.np_db)) +
        (tierCounts.free + Number(db.free_db));

      const totalQuestions = tierCounts.questionCount + Number(store.store_questions) + Number(eq.total_eq) + ppAlliedHealthTotal;

      const proof = {
        totalQuestions,
        totalFlashcards: Number(flashcardCount.rows[0]?.count) || 0,
        totalDecks: Number(deckCount.rows[0]?.count) || 0,
        totalLessons,
        hasCatExams: true,
        hasClinicalImages: true,
        hasMultiTierSupport: true,
        tiers: ["rpn", "rn", "np"],
        rpnQuestions: Number(eq.rpn_eq),
        rnQuestions: Number(eq.rn_eq),
        npQuestions: Number(eq.np_eq),
        lastUpdatedISO: new Date().toISOString(),
      };

      platformProofCache = { data: proof, timestamp: Date.now() };
      res.json(proof);
    } catch (error: any) {
      console.error("Platform proof error:", error);
      res.status(500).json({ error: "Failed to compute platform proof" });
    }
  });

  app.get("/api/admin/diagnostics", async (req, res) => {
    const admin = await requireAdmin(req, res);
    if (!admin) return;
    try {
      const dbStatus = await pool.query("SELECT 1 AS ok").then(() => "connected").catch(() => "error");

      const examByTier = await pool.query(
        `SELECT tier, status, COUNT(*)::int AS count FROM exam_questions GROUP BY tier, status ORDER BY tier, status`
      );

      const flashcardByStatus = await pool.query(
        `SELECT tier, status, COUNT(*)::int AS count FROM flashcard_bank GROUP BY tier, status ORDER BY tier, status`
      ).catch(() => ({ rows: [] }));

      const flashcardDecks = await pool.query(
        `SELECT COUNT(*)::int AS count FROM flashcard_decks`
      ).catch(() => ({ rows: [{ count: 0 }] }));

      const fs = await import("fs");
      const pathMod = await import("path");
      const { fileURLToPath } = await import("url");
      const currentDir = typeof __dirname !== "undefined" ? __dirname : pathMod.dirname(fileURLToPath(import.meta.url));
      const seedBases = [
        pathMod.resolve(currentDir, "seed-data/exam-questions"),
        pathMod.resolve(process.cwd(), "dist/seed-data/exam-questions"),
        pathMod.resolve(process.cwd(), "server/seed-data/exam-questions"),
      ];
      const seedFileExists = seedBases.flatMap(b => [b + ".json.gz", b + ".json"]).map(p => ({ path: p, exists: fs.existsSync(p) }));

      let migrationTimestamp: string | null = null;
      try {
        const { lastStartupMigrationTimestamp } = await import("./startup-data-migrations");
        migrationTimestamp = lastStartupMigrationTimestamp;
      } catch {}

      const explanationCoverage = await pool.query(`
        SELECT question_source as source,
          COUNT(*)::int as total,
          COUNT(*) FILTER (WHERE review_status = 'approved')::int as approved,
          COUNT(*) FILTER (WHERE review_status = 'pending')::int as pending,
          COUNT(*) FILTER (WHERE review_status = 'flagged')::int as flagged,
          COALESCE(AVG(COALESCE((quality_score->>'composite')::int, 0)), 0)::int as avg_quality
        FROM question_explanations GROUP BY question_source
      `).catch(() => ({ rows: [] }));

      const explanationTotals = await pool.query(`
        SELECT COUNT(*)::int as total FROM question_explanations
      `).catch(() => ({ rows: [{ total: 0 }] }));

      res.json({
        environment: process.env.NODE_ENV || "development",
        databaseStatus: dbStatus,
        databaseHost: (process.env.DATABASE_URL || "").replace(/\/\/.*@/, "//***@"),
        examQuestions: examByTier.rows,
        flashcardBank: flashcardByStatus.rows,
        flashcardDecksCount: flashcardDecks.rows[0]?.count || 0,
        seedFiles: seedFileExists,
        lastStartupMigrationTimestamp: migrationTimestamp,
        serverTime: new Date().toISOString(),
        explanationCoverage: explanationCoverage.rows,
        totalExplanations: explanationTotals.rows[0]?.total || 0,
      });
    } catch (e: any) {
      res.status(500).json({ error: e.message });
    }
  });

