              if (!q.rationaleCorrect || !Array.isArray(q.rationaleIncorrect)) continue;
              if (!q.clinicalPearl) continue;
              const qType = (q.type || "").toUpperCase();
              if (!VALID_TYPES.includes(qType)) q.type = "MCQ";
