  app.post("/api/stripe/create-checkout", stripeCheckoutLimiter, validateBody(stripeCreateCheckoutBodySchema), async (req, res) => {
    const isProduction = process.env.REPLIT_DEPLOYMENT === '1';
    const env = isProduction ? 'PRODUCTION' : 'DEVELOPMENT';

    try {
      const { userId, tier, duration, region, planId, source, successUrl: customSuccessUrl, cancelUrl: customCancelUrl } = req.body;
      const purchaseSource = (source === "mobile_app") ? "mobile_app" : "web";

      console.log(`[Checkout:${env}] Starting checkout — tier=${tier} duration=${duration} region=${region} planId=${planId} userId=${userId} source=${purchaseSource}`);

      const user = await storage.getUser(userId);
      if (!user) return res.status(404).json({ error: "User not found" });

      if (user.tier === "admin") {
        console.warn(`[Checkout:${env}] BLOCKED: Admin account ${user.id} (${user.username}) attempted to purchase tier=${tier}. Admin accounts already have full access.`);
        return res.status(400).json({
          error: "Admin accounts already have full access to all content. Subscriptions are for student accounts.",
          isAdmin: true,
        });
      }

      const subscriptionTiers = ["rpn", "rn", "np", "allied", "newgrad", "new_grad_toolkit", "certification_prep", "full_access"];
      if (subscriptionTiers.includes(tier)) {
        const dbPlansForValidation = await storage.getPricingPlansByTier(tier);
        const activePlansForTier = dbPlansForValidation.filter((p: PricingPlan) => p.isEnabled !== false);
        if (activePlansForTier.length === 0) {
          console.warn(`[Checkout:${env}] Rejected: tier=${tier} has no active plans in pricing_plans table`);
          return res.status(400).json({ error: "This plan is currently unavailable. Please choose a different plan." });
        }
        if (planId) {
          const matchingPlan = activePlansForTier.find((p: PricingPlan) => p.id === planId);
          if (!matchingPlan) {
            console.warn(`[Checkout:${env}] Rejected: planId=${planId} is not an active plan for tier=${tier}`);
            return res.status(400).json({ error: "The selected plan is inactive or does not exist. Please choose a different plan." });
          }
        }
      }

      let stripe;
      try {
        stripe = await getUncachableStripeClient();
      } catch (credErr: any) {
        console.error(`[Checkout:${env}] Stripe client initialization FAILED: ${credErr.message}`);
        const isTestKeyInProd = credErr.message?.includes('Test secret key') || credErr.message?.includes('Test publishable key');
        return res.status(503).json({
          error: isTestKeyInProd
            ? "Payment system has test keys configured in production. Live Stripe keys (sk_live_ / pk_live_) are required. Please update STRIPE_SECRET_KEY and STRIPE_PUBLISHABLE_KEY secrets."
            : "Payment system is temporarily unavailable. Please try again shortly or contact support.",
          detail: isProduction ? undefined : credErr.message,
        });
      }

      const credInfo = getCredentialInfo();
      console.log(`[Checkout:${env}] Stripe key type: ${credInfo.keyType}, prefix: ${credInfo.keyPrefix}, source: ${credInfo.source}`);

      if (isProduction && credInfo.keyType === 'TEST') {
        console.error(`[Checkout:${env}] FATAL: Test key used in production!`);
        return res.status(503).json({ error: "Payment system misconfigured. Please contact support." });
      }

      let customerId = user.stripeCustomerId;
      if (!customerId) {
        console.log(`[Checkout:${env}] Creating new Stripe customer for user ${user.id} (${user.email || 'no email'})`);
        const customer = await withTimeout(
          stripe.customers.create({
            email: user.email || undefined,
            metadata: { userId: user.id, username: user.username },
          }),
          10000,
          "stripe_customer_create"
        );
        await storage.updateUserStripeInfo(user.id, { stripeCustomerId: customer.id });
        customerId = customer.id;
        console.log(`[Checkout:${env}] Created Stripe customer: ${customer.id}`);
      }

      const isCAD = region === "CA";
      const currency = isCAD ? "cad" : "usd";

      const fallbackPriceTable: Record<string, Record<string, { CAD: number; USD: number }>> = {
        "lab-values": { monthly: { CAD: 999, USD: 999 } },
        "med-math": { monthly: { CAD: 999, USD: 999 } },
        "practice-tools": { monthly: { CAD: 1499, USD: 1499 } },
      };

      const tierNames: Record<string, string> = {
        rpn: "NurseNest RPN/LVN",
        rn: "NurseNest RN/NCLEX",
        np: "NurseNest NP Advanced",
        allied: "NurseNest Allied Health",
        new_grad_toolkit: "NurseNest New Grad Toolkit",
        certification_prep: "NurseNest Certification Prep",
        full_access: "NurseNest Full Access",
        "lab-values": "NurseNest Lab Interpretation Unlimited",
        "med-math": "NurseNest Med Math Unlimited",
        "practice-tools": "NurseNest All Practice Tools",
      };

      const selectedDuration = duration || "monthly";
      let amount: number;
      let isLifetimePlan = false;

      const dbPlans = await storage.getPricingPlansByTier(tier);
      const enabledPlans = dbPlans.filter((p: PricingPlan) => p.isEnabled !== false);
      const dbPlan: PricingPlan | undefined = planId
        ? enabledPlans.find((p: PricingPlan) => p.id === planId)
        : enabledPlans.find((p: PricingPlan) => p.duration === selectedDuration);

      if (dbPlan) {
        amount = isCAD ? dbPlan.priceCAD : dbPlan.priceUSD;
        isLifetimePlan = !!dbPlan.isLifetime;
        console.log(`[Checkout:${env}] DB plan found: id=${dbPlan.id} amount=${amount} currency=${currency} isLifetime=${isLifetimePlan}`);
      } else {
        const fallbackTierPrices = fallbackPriceTable[tier];
        if (!fallbackTierPrices) {
          console.error(`[Checkout:${env}] Invalid tier: ${tier} — no DB plan and no fallback`);
          return res.status(400).json({ error: `Invalid tier: ${tier}` });
        }
        const durationPrices = fallbackTierPrices[selectedDuration] || fallbackTierPrices["monthly"];
        if (!durationPrices) {
          console.error(`[Checkout:${env}] Invalid duration: ${selectedDuration} for tier ${tier}`);
          return res.status(400).json({ error: `Invalid duration: ${selectedDuration}` });
        }
        amount = isCAD ? durationPrices.CAD : durationPrices.USD;
        console.log(`[Checkout:${env}] Using fallback price: amount=${amount} currency=${currency}`);
      }

      const intervalMap: Record<string, { interval: "month" | "year"; interval_count: number }> = {
        monthly: { interval: "month", interval_count: 1 },
        "3-month": { interval: "month", interval_count: 3 },
        "6-month": { interval: "month", interval_count: 6 },
        yearly: { interval: "year", interval_count: 1 },
      };

      const durationLabels: Record<string, string> = {
        monthly: "Monthly",
        "3-month": "3-Month",
        "6-month": "6-Month",
        yearly: "Yearly",
      };

      const recurring = intervalMap[selectedDuration] || intervalMap["monthly"];
      const durationLabel = durationLabels[selectedDuration] || "Monthly";

      const baseUrl = process.env.SITE_URL || `${req.protocol}://${req.get("host")}`;
      const sourceParam = purchaseSource === "mobile_app" ? "&source=mobile_app" : "";

      let validatedSuccessUrl: string | null = null;
      let validatedCancelUrl: string | null = null;
      if (customSuccessUrl || customCancelUrl) {
        const allowedOrigins = [baseUrl];
        if (process.env.SITE_URL) allowedOrigins.push(process.env.SITE_URL);
        if (process.env.APP_RETURN_URL) allowedOrigins.push(process.env.APP_RETURN_URL);

        const isAllowedUrl = (url: string) => {
          try {
            const parsed = new URL(url);
            return allowedOrigins.some(origin => {
              try { return new URL(origin).origin === parsed.origin; } catch { return false; }
            });
          } catch { return false; }
        };

        if (customSuccessUrl && isAllowedUrl(customSuccessUrl)) {
          validatedSuccessUrl = customSuccessUrl;
        } else if (customSuccessUrl) {
          console.warn(`[Checkout:${env}] Rejected untrusted successUrl: ${customSuccessUrl}`);
        }
        if (customCancelUrl && isAllowedUrl(customCancelUrl)) {
          validatedCancelUrl = customCancelUrl;
        } else if (customCancelUrl) {
          console.warn(`[Checkout:${env}] Rejected untrusted cancelUrl: ${customCancelUrl}`);
        }
      }

      const successUrl = validatedSuccessUrl || `${baseUrl}/subscription/success?session_id={CHECKOUT_SESSION_ID}&tier=${tier}${sourceParam}`;
      const cancelUrl = validatedCancelUrl || `${baseUrl}/pricing`;

      console.log(`[Checkout:${env}] URLs — success: ${successUrl.substring(0, 60)}... cancel: ${cancelUrl}`);

      if (isProduction && !baseUrl.startsWith('https://')) {
        console.warn(`[Checkout:${env}] WARNING: baseUrl is not HTTPS: ${baseUrl}`);
      }

      const bnplPaymentMethods: string[] = ["card", "klarna", "afterpay_clearpay"];
      if (!isCAD) bnplPaymentMethods.push("affirm");

      let referralCouponId: string | undefined;
      if (user.referredBy && !user.referralDiscountUsed) {
        try {
          const coupons = await stripe.coupons.list({ limit: 100 });
          const existing15 = coupons.data.find((c: any) => c.metadata?.type === "nursenest_referral" && c.valid && c.percent_off === 15);
          if (existing15) {
            referralCouponId = existing15.id;
          } else {
            const coupon = await stripe.coupons.create({
              percent_off: 15,
              duration: "once",
              name: "Referral Discount - 15% Off",
              metadata: { type: "nursenest_referral" },
            });
            referralCouponId = coupon.id;
          }
        } catch (couponErr) {
          console.error("[Checkout] Failed to create/find referral coupon:", couponErr);
        }
      }

      if (isLifetimePlan || selectedDuration === "lifetime") {
        console.log(`[Checkout:${env}] Creating LIFETIME payment session — tier=${tier} amount=${amount} ${currency}`);
        const sessionOpts: any = {
          customer: customerId,
          payment_method_types: amount >= 100 ? bnplPaymentMethods : ["card"],
          line_items: [
            {
              price_data: {
                currency,
                product_data: {
                  name: `${tierNames[tier] || tier} - Lifetime Access`,
                  description: `Lifetime one-time purchase of ${tierNames[tier] || tier}. Never expires.`,
                },
                unit_amount: amount,
              },
              quantity: 1,
            },
          ],
          mode: "payment",
          allow_promotion_codes: !referralCouponId,
          success_url: successUrl + '&lifetime=true',
          cancel_url: cancelUrl,
          metadata: { userId: user.id, tier, duration: "lifetime", isLifetime: "true", purchaseSource, referredBy: user.referredBy || "" },
        };
        if (referralCouponId) {
          sessionOpts.discounts = [{ coupon: referralCouponId }];
        }
        const session = await stripe.checkout.sessions.create(sessionOpts);
        console.log(`[Checkout:${env}] Lifetime session created: ${session.id}`);
        return res.json({ url: session.url });
      }

      if (selectedDuration === "one-time" || tier === "lab-values" || tier === "med-math" || tier === "practice-tools") {
        console.log(`[Checkout:${env}] Creating ONE-TIME payment session — tier=${tier} amount=${amount} ${currency}`);
        const sessionOpts: any = {
          customer: customerId,
          payment_method_types: amount >= 100 ? bnplPaymentMethods : ["card"],
          line_items: [
            {
              price_data: {
                currency,
                product_data: {
                  name: tierNames[tier] || tier,
                  description: `One-time access to ${tierNames[tier] || tier}`,
                },
                unit_amount: amount,
              },
              quantity: 1,
            },
          ],
          mode: "payment",
          allow_promotion_codes: !referralCouponId,
          success_url: successUrl,
          cancel_url: cancelUrl,
          metadata: { userId: user.id, tier, duration: selectedDuration, purchaseSource, referredBy: user.referredBy || "" },
        };
        if (referralCouponId) {
          sessionOpts.discounts = [{ coupon: referralCouponId }];
        }
        const session = await stripe.checkout.sessions.create(sessionOpts);
        console.log(`[Checkout:${env}] One-time session created: ${session.id}`);
        return res.json({ url: session.url });
      }

      const dbStripePriceId = dbPlan
        ? (isCAD ? dbPlan.stripePriceIdCad : dbPlan.stripePriceIdUsd) ?? null
        : null;
      const stripePriceId = dbStripePriceId || getStripePriceId(tier, selectedDuration, currency);

      if (stripePriceId) {
        if (isProduction && stripePriceId.startsWith('price_') && !stripePriceId.includes('test')) {
          console.log(`[Checkout:${env}] Using Stripe Price ID: ${stripePriceId} for ${tier}/${selectedDuration}/${currency}`);
        } else if (isProduction) {
          console.warn(`[Checkout:${env}] Price ID ${stripePriceId} may be a test price in production — proceeding with caution`);
        } else {
          console.log(`[Checkout:${env}] Using Stripe Price ID: ${stripePriceId} for ${tier}/${selectedDuration}/${currency}`);
        }
      } else {
        const missingKey = `tier=${tier} interval=${selectedDuration} currency=${currency}`;
        console.warn(`[Checkout:${env}] Missing live price ID for ${missingKey} — using inline price_data fallback (amount=${amount})`);
      }

      const lineItem: any = stripePriceId
        ? { price: stripePriceId, quantity: 1 }
        : {
            price_data: {
              currency,
              product_data: {
                name: tierNames[tier],
                description: `${durationLabel} subscription to ${tierNames[tier]} content`,
              },
              unit_amount: amount,
              recurring: { interval: recurring.interval, interval_count: recurring.interval_count },
            },
            quantity: 1,
          };

      console.log(`[Checkout:${env}] Creating SUBSCRIPTION session — tier=${tier} duration=${selectedDuration} amount=${amount} ${currency} customer=${customerId}`);

      const subscriptionOpts: any = {
        customer: customerId,
        payment_method_types: ["card"],
        line_items: [lineItem],
        mode: "subscription",
        allow_promotion_codes: !referralCouponId,
        success_url: successUrl,
        cancel_url: cancelUrl,
        metadata: { userId: user.id, tier, duration: selectedDuration, purchaseSource, referredBy: user.referredBy || "" },
        subscription_data: {
          metadata: { userId: user.id, tier, duration: selectedDuration, purchaseSource },
        },
      };
      if (referralCouponId) {
        subscriptionOpts.discounts = [{ coupon: referralCouponId }];
      }
      const session = await withTimeout(
        stripe.checkout.sessions.create(subscriptionOpts),
        10000,
        "stripe_checkout_create"
      );
      console.log(`[Checkout:${env}] Subscription session created: ${session.id}`);

      res.json({ url: session.url });
    } catch (e: any) {
      const errorDetail = {
        env,
        message: e.message,
        type: e.type || 'unknown',
        code: e.code || null,
        statusCode: e.statusCode || null,
        tier: req.body?.tier,
        duration: req.body?.duration,
        region: req.body?.region,
        userId: req.body?.userId,
        stack: e.stack?.split('\n').slice(0, 5).join('\n'),
      };
      emitStructuredLog(
        {
          level: "error",
          type: "stripe_checkout_error",
          provider: "stripe",
          route: "POST /api/stripe/create-checkout",
          requestId: req.requestId,
          userId: errorDetail.userId,
          msg: "create-checkout failed",
          reason: e?.message,
          detail: errorDetail,
        },
        "error",
      );

      if (e.type === 'StripeAuthenticationError') {
        emitStructuredLog(
          {
            level: "error",
            type: "stripe_auth_error",
            provider: "stripe",
            route: "POST /api/stripe/create-checkout",
            requestId: req.requestId,
            msg: "Stripe secret key invalid or revoked",
          },
          "error",
        );
        res.status(503).json({
          error: "Payment system authentication failed. The API key may be invalid or expired. Please contact support.",
          stripeError: isProduction ? undefined : e.message,
        });
      } else if (e.type === 'StripeInvalidRequestError') {
        emitStructuredLog(
          {
            level: "error",
            type: "stripe_invalid_request",
            provider: "stripe",
            route: "POST /api/stripe/create-checkout",
            requestId: req.requestId,
            msg: e.message,
          },
          "error",
        );
        res.status(400).json({
          error: isProduction
            ? "There was a problem with the checkout configuration. Please try again or contact support."
            : `Checkout configuration error: ${e.message}`,
        });
      } else if (e.message?.includes('credentials') || e.message?.includes('connection not found')) {
        res.status(503).json({ error: "Payment system temporarily unavailable. Please try again shortly." });
      } else if (e.message?.includes('No such price')) {
        const missingId = e.message.match(/price_\w+/)?.[0] || 'unknown';
        emitStructuredLog(
          {
            level: "error",
            type: "stripe_invalid_price",
            provider: "stripe",
            route: "POST /api/stripe/create-checkout",
            requestId: req.requestId,
            msg: "Invalid price ID",
            reason: missingId,
          },
          "error",
        );
        res.status(400).json({ error: `Invalid price configuration (${missingId}). Please refresh and try again.` });
      } else {
        res.status(500).json({
          error: "Failed to create checkout session. Please try again.",
          stripeError: isProduction ? undefined : e.message,
        });
      }
    }
  });

  app.post("/api/stripe/verify-session", validateBody(stripeVerifySessionBodySchema), async (req, res) => {
    try {
      const { sessionId, userId, tier } = req.body;
      const user = await storage.getUser(userId);
      const isAdmin = user?.tier === "admin";

      emitStructuredLog({
        level: "info",
        type: "stripe_verify_session_start",
        provider: "stripe",
        route: "POST /api/stripe/verify-session",
        requestId: req.requestId,
        userId,
        msg: "verify-session started",
        tier,
        sessionId,
        currentTier: user?.tier,
        isAdmin,
      });

      const stripe = await getUncachableStripeClient();
      const session = await withTimeout(
        stripe.checkout.sessions.retrieve(sessionId),
        10000,
        "stripe_session_retrieve"
      );

      emitStructuredLog({
        level: "info",
        type: "stripe_session_retrieved",
        provider: "stripe",
        route: "POST /api/stripe/verify-session",
        requestId: req.requestId,
        userId,
        msg: "session retrieved",
        payment_status: session.payment_status,
        mode: session.mode,
        subscription: session.subscription || null,
      });

      if (session.payment_status === "paid") {
        const isLifetime = session.metadata?.isLifetime === "true";

        const effectiveTier = isAdmin ? "admin" : tier;
        emitStructuredLog({
          level: "info",
          type: "stripe_verify_payment_confirmed",
          provider: "stripe",
          route: "POST /api/stripe/verify-session",
          requestId: req.requestId,
          userId,
          msg: "payment confirmed",
          isLifetime,
          effectiveTier,
          preserveAdmin: isAdmin,
        });

        if (isLifetime) {
          await storage.setUserLifetime(userId);
          if (!isAdmin) {
            await storage.updateUserTier(userId, tier);
          }
        } else {
          await storage.updateUserStripeInfo(userId, {
            stripeSubscriptionId: session.subscription as string,
            subscriptionStatus: "active",
            ...(isAdmin ? {} : { tier }),
          });
        }

        const paidUser = await storage.getUser(userId);
        emitStructuredLog({
          level: "info",
          type: "stripe_verify_db_complete",
          provider: "stripe",
          route: "POST /api/stripe/verify-session",
          requestId: req.requestId,
          userId,
          msg: "db write complete",
          tier: paidUser?.tier,
          subscriptionStatus: paidUser?.subscriptionStatus,
          stripeSubId: paidUser?.stripeSubscriptionId || null,
        });

        if (paidUser?.referredBy && !paidUser.referralDiscountUsed) {
          try {
            await storage.markReferralDiscountUsed(userId);
          } catch (e) {
            emitStructuredLog(
              {
                level: "error",
                type: "stripe_verify_referral_mark_failed",
                provider: "stripe",
                route: "POST /api/stripe/verify-session",
                requestId: req.requestId,
                userId,
                msg: "mark referral discount failed",
                reason: e instanceof Error ? e.message : String(e),
              },
              "error",
            );
          }
        }
        res.json({ success: true, tier: effectiveTier, isLifetime });
      } else {
        emitStructuredLog(
          {
            level: "warn",
            type: "stripe_verify_not_paid",
            provider: "stripe",
            route: "POST /api/stripe/verify-session",
            requestId: req.requestId,
            userId,
            msg: "payment not paid",
            reason: session.payment_status,
          },
          "warn",
        );
        res.json({ success: false, error: `Payment status: ${session.payment_status}` });
      }
    } catch (e: any) {
      emitStructuredLog(
        {
          level: "error",
          type: "stripe_verify_error",
          provider: "stripe",
          route: "POST /api/stripe/verify-session",
          requestId: req.requestId,
          msg: e?.message,
          stripeErrorType: e?.type || "unknown",
        },
        "error",
      );
      const isProduction = process.env.REPLIT_DEPLOYMENT === '1';
      if (e.type === 'StripeAuthenticationError') {
        res.status(503).json({ error: "Payment verification temporarily unavailable. Your subscription will activate automatically. If it doesn't appear within a few minutes, please contact support." });
      } else {
        res.status(500).json({ error: isProduction ? "Verification temporarily unavailable. If you were charged, your subscription will activate shortly." : e.message });
      }
    }
  });

  app.post("/api/stripe/portal", validateBody(stripePortalBodySchema), async (req, res) => {
    try {
      const { userId } = req.body;
      const user = await storage.getUser(userId);
      if (!user?.stripeCustomerId) return res.status(400).json({ error: "No subscription found" });

      const stripe = await getUncachableStripeClient();
      const portalSession = await stripe.billingPortal.sessions.create({
        customer: user.stripeCustomerId,
        return_url: `${req.protocol}://${req.get("host")}/lessons`,
      });

      res.json({ url: portalSession.url });
    } catch (e: any) {
      res.status(500).json({ error: e.message });
    }
  });

  app.get("/api/subscription/:userId", async (req, res) => {
    try {
      const user = await storage.getUser(req.params.userId);
      if (!user) return res.status(404).json({ error: "User not found" });

      let daysRemaining: number | null = null;
      let currentPeriodEnd: string | null = null;

      if (user.stripeSubscriptionId) {
        try {
          const { db: pgPool } = await import("./storage");
          const result = await pgPool.execute(
            sql`SELECT current_period_end, status FROM stripe.subscriptions WHERE id = ${user.stripeSubscriptionId} LIMIT 1`,
          );
          if (result.rows && result.rows.length > 0) {
            const sub = result.rows[0] as any;
            if (sub.current_period_end) {
              const endDate = new Date(sub.current_period_end * 1000);
              currentPeriodEnd = endDate.toISOString();
              const now = new Date();
              daysRemaining = Math.max(
                0,
                Math.ceil((endDate.getTime() - now.getTime()) / (1000 * 60 * 60 * 24)),
              );
            }
          }
        } catch {
          // Stripe sync table might not be available yet; ignore
        }
      }

      res.json({
        tier: user.tier || "free",
        subscriptionStatus: user.subscriptionStatus || "inactive",
        hasAccess: user.subscriptionStatus === "active",
        daysRemaining,
        currentPeriodEnd,
      });
    } catch (e: any) {
      res.status(500).json({ error: e.message });
    }
  });

