  // --------------------
  // Content - General
  // --------------------
  app.get("/api/content", async (req, res) => {
    try {
      res.setHeader("Cache-Control", "no-cache, no-store, must-revalidate");
      res.setHeader("Pragma", "no-cache");
      const { status, type, category } = req.query;

      const CONTENT_COLUMNS = "id, title, slug, type, category, body_system, tier, status, tags, summary, seo_title, seo_description, seo_keywords, primary_keyword, secondary_keywords, scheduled_at, clinical_safety_review, auto_publish, created_at, updated_at, published_at, region_scope";
      const contentLimit = Math.min(parseInt(req.query.limit as string) || 500, 1000);
      const contentOffset = Math.max(parseInt(req.query.offset as string) || 0, 0);

      if (status === "all") {
        const admin = await requireAdmin(req, res);
        if (!admin) return;
        let items: any[] = [];
        let total = 0;
        try {
          const countResult = await pool.query(`SELECT COUNT(*) FROM content_items`);
          total = parseInt(countResult.rows[0]?.count || "0", 10);
          const result = await pool.query(`SELECT ${CONTENT_COLUMNS} FROM content_items ORDER BY updated_at DESC NULLS LAST LIMIT $1 OFFSET $2`, [contentLimit, contentOffset]);
          items = snakeToCamel(result.rows);
        } catch (e: any) {
          console.error("[Content API] Admin raw SQL error:", e.message);
          try {
            items = await storage.getAllContentItems(contentLimit, contentOffset);
            total = -1;
          } catch {}
        }
        console.log(`[Content API] Admin fetch returned ${items.length} items (total=${total}, offset=${contentOffset}, limit=${contentLimit})`);
        return res.json({ items, total, offset: contentOffset, limit: contentLimit });
      }

      const region = req.region || "US";
      const regionFilter = buildRegionFilter(region);
      let items: any[] = [];
      const lang = (req.query.lang as string) || req.lang || "en";
      const sqlFilters: string[] = [];
      try {
        let q = `SELECT ${CONTENT_COLUMNS} FROM content_items WHERE status = 'published' AND status != 'quarantined' AND ${regionFilter}`;
        const params: any[] = [];
        if (type) {
          params.push(type as string);
          q += ` AND type = $${params.length}`;
          sqlFilters.push(`type=${type}`);
        }
        if (category) {
          params.push(category as string);
          q += ` AND category = $${params.length}`;
          sqlFilters.push(`category=${category}`);
        }
        if (type === "lesson" || type === "lessons") {
          const userTier = await extractUserTier(req);
          const effectiveTier = userTier || "free";
          const allowedTiers = effectiveTier === "admin"
            ? ["free", "general", "rpn", "rn", "np"]
            : effectiveTier === "free"
              ? ["free", "general"]
              : ["free", "general", effectiveTier];
          const tierPlaceholders = allowedTiers.map((t) => { params.push(t); return `$${params.length}`; }).join(",");
          q += ` AND COALESCE(tier, 'free') IN (${tierPlaceholders})`;
          sqlFilters.push(`tier IN [${allowedTiers.join(",")}]`);
        }
        if (lang !== "en") {
          q += ` AND id IN (SELECT content_item_id FROM content_item_translations WHERE locale = $${params.length + 1} AND translation_status IN ('approved', 'reviewed'))`;
          params.push(lang);
          sqlFilters.push(`lang=${lang}`);
        }
        q += " ORDER BY published_at DESC NULLS LAST";
        params.push(contentLimit);
        q += ` LIMIT $${params.length}`;
        params.push(contentOffset);
        q += ` OFFSET $${params.length}`;
        const result = await pool.query(q, params);
        items = snakeToCamel(result.rows);
      } catch (sqlErr: any) {
        console.error("[Content API] SQL error:", sqlErr.message);
      }

      console.log(`[Content API] Returned ${items.length} items | type=${type || "all"} | region=${region} | lang=${lang} | sqlFilters=[${sqlFilters.join(", ")}] | limit=${contentLimit} | offset=${contentOffset}`);

      if (lang !== "en" && items.length > 0) {
        const contentIds = items.map((item: any) => item.id);
        const translatedFieldsMap = await getBulkTranslatedFields("content_item", contentIds, lang);
        for (const item of items) {
          const fields = translatedFieldsMap.get(item.id);
          if (fields && Object.keys(fields).length > 0) {
            if (fields.title) { item._originalTitle = item.title; item.title = fields.title; }
            if (fields.summary) { item._originalSummary = item.summary; item.summary = fields.summary; }
            if (fields.seoTitle) item.seoTitle = fields.seoTitle;
            if (fields.seoDescription) item.seoDescription = fields.seoDescription;
            item._translationStatus = "translated";
          } else {
            item._translationStatus = "missing";
          }
        }
      } else {
        for (const item of items) {
          item._translationStatus = lang === "en" ? "source" : "missing";
        }
      }

      res.json(items);
    } catch (e: any) {
      console.error("Content API error:", e.message);
      res.status(500).json({ error: e.message });
    }
  });

  app.post("/api/content/check-duplicate", async (req, res) => {
    try {
      const { slug, primaryKeyword, excludeId } = req.body;
      const slugExists = slug ? await storage.checkDuplicateSlug(slug, excludeId) : false;
      const keywordOverlap = primaryKeyword ? await storage.checkKeywordOverlap(primaryKeyword, excludeId) : [];
      res.json({
        slugExists,
        keywordOverlap: keywordOverlap.map((i) => ({ id: i.id, title: i.title, primaryKeyword: i.primaryKeyword })),
      });
    } catch (e: any) {
      res.status(500).json({ error: e.message });
    }
  });

  app.get("/api/content/:id", blockMixedLanguageRender, async (req, res) => {
    const contentEnd = instrumentCorePath("lesson_page_load");
    try {
      const item = await storage.getContentItem(routeParamString(req.params.id));
      if (!item) return res.status(404).json({ error: "Content not found" });

      if (item.status !== "published") {
        const admin = await requireAdmin(req, res);
        if (!admin) return;
      }

      if (item.tier && item.tier !== "free") {
        const userTier = await extractUserTier(req);
        if (!canAccessTier(userTier, item.tier)) {
          return res.status(403).json({ error: "Upgrade required", requiredTier: item.tier });
        }
      }

      type ContentItemApiPayload = ContentItem & {
        _originalTitle?: string;
        _translationStatus?: "translated" | "missing" | "source";
      };

      const payload: ContentItemApiPayload = { ...item };

      const lang = (req.query.lang as string) || req.lang || "en";
      if (lang !== "en") {
        const translatedFields = await getTranslatedFields("content_item", item.id, lang);
        if (translatedFields && Object.keys(translatedFields).length > 0) {
          if (translatedFields.title) {
            payload._originalTitle = item.title;
            payload.title = translatedFields.title.text;
          }
          if (translatedFields.summary) payload.summary = translatedFields.summary.text;
          payload._translationStatus = "translated";
        } else {
          payload._translationStatus = "missing";
        }
      } else {
        payload._translationStatus = "source";
      }

      contentEnd();
      res.json(payload);
    } catch (e: any) {
      contentEnd();
      res.status(500).json({ error: e.message });
    }
  });

  app.get("/api/content/slug/:slug", blockMixedLanguageRender, async (req, res) => {
    try {
      let item: any = null;
      try {
        item = await storage.getContentItemBySlug(routeParamString(req.params.slug));
      } catch (ormErr: any) {
        console.error("Drizzle ORM slug fetch error:", ormErr.message);
      }

      if (!item) {
        try {
          const result = await pool.query("SELECT id, title, slug, type, category, body_system, tier, status, tags, summary, content, seo_title, seo_description, seo_keywords, primary_keyword, secondary_keywords, scheduled_at, clinical_safety_review, auto_publish, created_at, updated_at, published_at, region_scope FROM content_items WHERE slug = $1 LIMIT 1", [routeParamString(req.params.slug)]);
          item = result.rows[0] ? snakeToCamel(result.rows[0]) : null;
        } catch (sqlErr: any) {
          console.error("Raw SQL slug fetch error:", sqlErr.message);
        }
      }

      if (!item) {
        try {
          const { normalizeForAlias } = await import("./title-canonicalizer");
          const normalizedSlug = normalizeForAlias(routeParamString(req.params.slug));
          const aliasResult = await pool.query(
            `SELECT canonical_slug FROM lesson_aliases WHERE normalized_alias = $1 LIMIT 1`,
            [normalizedSlug]
          );
          if (aliasResult.rows.length > 0) {
            const canonicalSlug = aliasResult.rows[0].canonical_slug;
            return res.redirect(301, `/api/content/slug/${canonicalSlug}`);
          }
        } catch (aliasErr: any) {
          console.warn("[ContentSlug] Alias redirect error:", aliasErr.message);
        }
      }

      if (!item) return res.status(404).json({ error: "Content not found" });

      const requestingUserTier = await extractUserTier(req);
      const { isPreview: isInPreview, realTier } = await getEffectiveTier(req);
      const isRealAdmin = realTier === "admin";

      if (item.status === "quarantined" && !isRealAdmin) {
        try {
          const quarantineCheck = await getContentWithQuarantineCheck(item.id, item.type || "lesson");
          if (quarantineCheck.quarantined && quarantineCheck.fallback) {
            res.setHeader("X-Content-Source", "quarantine-fallback");
            return res.json({
              ...quarantineCheck.fallback,
              _quarantineFallback: true,
              _message: quarantineCheck.message,
            });
          }
        } catch {}
      }

      if (item.status !== "published" && !isRealAdmin) {
        return res.status(404).json({ error: "Content not found" });
      }

      const region = req.region || "US";
      if (!isRealAdmin && !isRegionAllowed(item.regionScope || item.region_scope, region)) {
        return res.status(404).json({ error: "Content not found" });
      }

      if (item.tier && item.tier !== "free") {
        const tierToCheck = isInPreview ? requestingUserTier : (isRealAdmin ? "admin" : requestingUserTier);
        if (!canAccessTier(tierToCheck, item.tier)) {
          const previewItem: any = {
            id: item.id,
            slug: item.slug,
            title: item.title,
            category: item.category,
            tier: item.tier,
            status: item.status,
            summary: item.summary || null,
            imageUrl: item.imageUrl || item.image_url || null,
            imageAlt: item.imageAlt || item.image_alt || null,
            seoTitle: item.seoTitle || item.seo_title || null,
            seoDescription: item.seoDescription || item.seo_description || null,
            isPreviewOnly: true,
            requiredTier: item.tier,
          };
          if (item.definition) previewItem.definition = item.definition;
          return res.json(previewItem);
        }
      }

      const lang = req.lang || "en";
      if (lang !== "en") {
        const contentId = item.id;
        const translations = await getTranslatedFields("content_item", contentId, lang);

        const hasOutdated = Object.values(translations).some(
          (t: any) => t.status === "outdated" || t.status === "stale"
        );

        if (!hasOutdated) {
          if (translations.title?.text) item.title = translations.title.text;
          if (translations.summary?.text) item.summary = translations.summary.text;
          if (translations.seoTitle?.text) item.seoTitle = translations.seoTitle.text;
          if (translations.seoDescription?.text) item.seoDescription = translations.seoDescription.text;
          if (translations.content?.text) {
            try {
              item.content = JSON.parse(translations.content.text);
            } catch {}
          }
        }

        const sourceFields: Record<string, string | null | undefined> = {
          title: item.title,
          summary: item.summary,
          seoTitle: item.seoTitle,
          seoDescription: item.seoDescription,
        };
        const translationStatusInfo = await getTranslationStatus("content_item", contentId, lang, sourceFields);
        const availableLanguages = await getAvailableLanguages("content_item", contentId);

        item._translation = {
          lang,
          status: translationStatusInfo.status,
          missingFields: translationStatusInfo.missing,
          staleFields: translationStatusInfo.stale,
          availableLanguages,
          isOutdated: hasOutdated,
        };
        item._translationStatus = translationStatusInfo.status === "complete" ? "translated"
          : translationStatusInfo.status === "stale" ? "stale"
          : translationStatusInfo.status === "missing" ? "missing" : "partial";
      } else {
        item._translation = {
          lang: "en",
          status: "complete",
          missingFields: [],
          staleFields: [],
          availableLanguages: await getAvailableLanguages("content_item", item.id),
          isOutdated: false,
        };
        item._translationStatus = "source";
      }

      res.json(item);
    } catch (e: any) {
      res.status(500).json({ error: e.message });
    }
  });

  app.get("/api/content/slug/:slug/related", async (req, res) => {
    try {
      const currentSlug = req.params.slug;
      const currentResult = await pool.query(
        `SELECT slug, title, category, tags FROM content_items WHERE slug = $1 AND status = 'published' LIMIT 1`,
        [currentSlug]
      );
      if (currentResult.rows.length === 0) return res.json([]);
      const current = currentResult.rows[0];

      const currentCategory = (current.category || "").toLowerCase();
      const currentTags: string[] = (Array.isArray(current.tags) ? current.tags : []).map((t: string) => t.toLowerCase());

      const relatedResult = await pool.query(
        `SELECT id, slug, title, category, seo_description AS summary, tags
         FROM content_items
         WHERE status = 'published' AND type IN ('blog', 'blog-post', 'article')
           AND slug IS NOT NULL AND slug != $1
           AND length(COALESCE(content::text, '')) >= 5000
         ORDER BY
           CASE WHEN lower(category) = $2 THEN 3 ELSE 0 END DESC,
           published_at DESC NULLS LAST
         LIMIT 20`,
        [currentSlug, currentCategory]
      );

      const scored = relatedResult.rows.map((c: any) => {
        let score = 0;
        if (currentCategory && (c.category || "").toLowerCase() === currentCategory) score += 3;
        const cTags: string[] = (Array.isArray(c.tags) ? c.tags : []).map((t: string) => t.toLowerCase());
        for (const tag of cTags) {
          if (currentTags.includes(tag)) score += 2;
        }
        return { slug: c.slug, title: c.title, category: c.category, summary: c.summary || "", score };
      });

      scored.sort((a: any, b: any) => b.score - a.score);
      const top: any[] = scored.slice(0, 4).filter((s: any) => s.score > 0);
      if (top.length < 3) {
        const remaining = scored.filter((s: any) => !top.includes(s)).slice(0, 4 - top.length);
        top.push(...remaining);
      }

      let relatedItems = top.slice(0, 4);
      const lang = (req.query.lang as string) || req.lang || "en";

      if (lang !== "en" && relatedItems.length > 0) {
        const slugToId = new Map<string, string>();
        for (const c of relatedResult.rows) {
          if (c.slug && c.id) slugToId.set(c.slug, String(c.id));
        }
        const itemIds = relatedItems.map((r: any) => slugToId.get(r.slug)).filter(Boolean) as string[];
        if (itemIds.length > 0) {
          const translationStatuses = await getBulkTranslationStatuses("content_item", itemIds, lang);
          relatedItems = relatedItems.filter((r: any) => {
            const id = slugToId.get(r.slug);
            return id && translationStatuses.get(id) === "translated";
          });
        }
        for (const item of relatedItems) {
          item._translationStatus = "translated";
        }
      } else {
        for (const item of relatedItems) {
          item._translationStatus = lang === "en" ? "source" : "missing";
        }
      }

      res.setHeader("Cache-Control", "public, max-age=3600");
      res.json(relatedItems);
    } catch (e: any) {
      res.status(500).json({ error: e.message });
    }
  });

  app.post("/api/content", validateBody(postContentBodySchema), async (req, res) => {
    try {
      const admin = await requireAdmin(req, res);
      if (!admin) return;

      const { username, password, ...contentData } = req.body;
      void username;
      void password;

      const validScopes = ["BOTH", "US_ONLY", "CA_ONLY"];
      const region = req.region || "US";
      const tierLower = (contentData.tier || "free").toLowerCase();
      const isRegionLockedTier = tierLower === "rpn" || tierLower === "rn" || tierLower === "lvn";
      if (isRegionLockedTier) {
        contentData.regionScope = `${region}_ONLY`;
      } else if (!contentData.regionScope) {
        contentData.regionScope = getDefaultRegionScope(contentData.tier, region);
      } else if (!validScopes.includes(contentData.regionScope)) {
        contentData.regionScope = "BOTH";
      }
      const parsed = insertContentItemSchema.parse(contentData);

      if (parsed.slug) {
        const timestampSlugMatch = parsed.slug.match(/^(.+)-(\d{13})$/);
        if (timestampSlugMatch) {
          const cleanSlug = timestampSlugMatch[1];
          const existingClean = await storage.getContentItemBySlug(cleanSlug);
          if (existingClean) {
            return res.status(409).json({
              error: `Slug "${parsed.slug}" contains a timestamp suffix. A clean version "${cleanSlug}" already exists.`,
              code: "DUPLICATE_TIMESTAMP_SLUG",
              canonicalSlug: cleanSlug,
            });
          }
          parsed.slug = cleanSlug;
        }
      }

      if (parsed.type === "lesson" && parsed.title && !contentData.forcePublish) {
        try {
          const { validateLessonTitle } = await import("./title-canonicalizer");
          const validation = validateLessonTitle(parsed.title);
          if (!validation.valid) {
            return res.status(422).json({
              error: `Title validation failed: ${validation.errors.join("; ")}`,
              suggestions: validation.suggestions,
              code: "LESSON_TITLE_INVALID",
            });
          }
        } catch (validationErr: any) {
          console.warn("[TitleValidation] Error during title validation:", validationErr.message);
        }
      }

      if (parsed.status === "published" && parsed.type === "lesson") {
        const lessonMinWords = parseInt(process.env.LESSON_MIN_WORDS || "100", 10);
        const bodyText = extractTextFromContent(parsed.content);
        const wc = countWords(bodyText);
        if (!parsed.title || !parsed.title.trim()) {
          return res.status(422).json({ error: "Lesson title is required for publishing.", code: "LESSON_MISSING_TITLE" });
        }
        if (!parsed.slug || !parsed.slug.trim()) {
          return res.status(422).json({ error: "Lesson slug is required for publishing.", code: "LESSON_MISSING_SLUG" });
        }
        if (!contentData.forcePublish) {
          const validTiers = ["free", "rpn", "rn", "np", "lvn", "allied"];
          if (!parsed.tier || !parsed.tier.trim()) {
            return res.status(422).json({ error: "A tier (rpn, rn, np, free) is required to publish a lesson.", code: "LESSON_MISSING_TIER" });
          }
          if (!validTiers.includes(parsed.tier.toLowerCase())) {
            return res.status(422).json({ error: `Invalid tier "${parsed.tier}". Must be one of: ${validTiers.join(", ")}`, code: "LESSON_INVALID_TIER" });
          }
          const cat = (parsed as any).category || (parsed as any).bodySystem;
          if (!cat || !cat.trim()) {
            return res.status(422).json({ error: "A category or body_system is required to publish a lesson.", code: "LESSON_MISSING_CATEGORY" });
          }
          if (cat.toLowerCase() === "general" || cat.toLowerCase() === "other") {
            return res.status(422).json({ error: `Category "${cat}" is too generic. Please assign a specific body system or topic category.`, code: "LESSON_GENERIC_CATEGORY" });
          }
        }
        const charCount = bodyText.length;
        if (charCount < 200 && !contentData.forcePublish) {
          return res.status(422).json({
            error: `Lesson content has ${charCount} characters, minimum 200 required for publishing.`,
            charCount,
            minimum: 200,
            code: "LESSON_CONTENT_TOO_SHORT",
          });
        }
        if (wc < lessonMinWords && !contentData.forcePublish) {
          return res.status(422).json({
            error: `Lesson has ${wc} words, minimum ${lessonMinWords} required for publishing. Save as draft or use forcePublish to bypass.`,
            wordCount: wc,
            minimum: lessonMinWords,
            code: "LESSON_TOO_SHORT",
          });
        }
      }

      const contentTypeForValidation = parsed.type === "lesson" ? "lesson" : parsed.type?.includes("blog") ? "blog" : parsed.type === "flashcard-set" ? "flashcard" : parsed.type || "";
      const { repairedData: repairedParsed, repairs: createRepairs } = autoRepairContent(contentTypeForValidation, parsed);

      if (repairedParsed.status === "published") {
        const validation = validateForPublish(contentTypeForValidation, repairedParsed);
        if (!validation.valid) {
          return res.status(422).json({
            error: "Content validation failed. Fix critical errors before publishing.",
            code: "VALIDATION_FAILED",
            validation,
            forcePublishBypassed: !!contentData.forcePublish,
          });
        }

        try {
          const { checkPublishingGate } = await import("./translation-completeness-routes");
          const translationGate = await checkPublishingGate("content_item", repairedParsed.slug || "");
          if (!translationGate.canPublish && translationGate.failures.length > 0) {
            const failureDetails = translationGate.failures.slice(0, 5).map(f => `${f.locale}: ${f.percentage}%`).join(", ");
            console.warn(`[PublishGate] Translation completeness below threshold for ${repairedParsed.slug}: ${failureDetails}`);
          }
        } catch (gateErr: any) {
          console.warn("[PublishGate] Translation gate check failed (non-blocking):", gateErr.message);
        }
      }

      const existingBySlug = repairedParsed.slug ? await storage.getContentItemBySlug(repairedParsed.slug) : undefined;
      let item;
      if (existingBySlug) {
        await saveRevision(existingBySlug.id, existingBySlug, admin);
        item = await storage.updateContentItem(existingBySlug.id, repairedParsed);
        await logAudit(req, admin, "content", item.id, "update", { title: existingBySlug.title, status: existingBySlug.status }, { title: item.title, type: item.type, status: item.status, regionScope: item.regionScope });
      } else {
        item = await storage.createContentItem(repairedParsed);
        await logAudit(req, admin, "content", item.id, "create", null, { title: item.title, type: item.type, status: item.status, regionScope: item.regionScope });
      }

      if (createRepairs.length > 0) {
        await logAutoRepairs(contentTypeForValidation, item.id, createRepairs);
      }

      if (item.status === "published") {
        try {
          const { generateRenderPayloads } = await import("./content-failover");
          await generateRenderPayloads(item.id);
          await createContentSnapshot(item.id, contentTypeForValidation, item, "publish");
        } catch (payloadErr: any) {
          console.error("[Content] Render payload generation error:", payloadErr.message);
        }
      }

      cacheInvalidate("lessons:");
      cacheInvalidate("flashcard-sets:");
      cacheInvalidate("exams:");
      res.json(item);
    } catch (e: any) {
      res.status(400).json({ error: e.message });
    }
  });

  app.put("/api/content/:id", validateBody(putContentBodySchema), async (req, res) => {
    try {
      const admin = await requireAdmin(req, res);
      if (!admin) return;

      const { username, password, ...contentData } = req.body;
      void username;
      void password;

      const existing = await storage.getContentItem(routeParamString(req.params.id));
      if (existing) {
        await saveRevision(routeParamString(req.params.id), existing, admin);
        const region = req.region || "US";
        const existingTier = (existing.tier || "free").toLowerCase();
        const updateTier = (contentData.tier || existingTier).toLowerCase();
        const isLockedTier = updateTier === "rpn" || updateTier === "rn" || updateTier === "lvn";
        if (isLockedTier) {
          contentData.regionScope = `${region}_ONLY`;
        } else if (contentData.regionScope) {
          const validScopes = ["BOTH", "US_ONLY", "CA_ONLY"];
          if (!validScopes.includes(contentData.regionScope)) {
            contentData.regionScope = existing.regionScope || "BOTH";
          }
        }
      }

      if (contentData.slug) {
        const timestampSlugMatch = contentData.slug.match(/^(.+)-(\d{13})$/);
        if (timestampSlugMatch) {
          const cleanSlug = timestampSlugMatch[1];
          const existingClean = await storage.getContentItemBySlug(cleanSlug);
          if (existingClean && existingClean.id !== routeParamString(req.params.id)) {
            return res.status(409).json({
              error: `Slug "${contentData.slug}" contains a timestamp suffix. A clean version "${cleanSlug}" already exists.`,
              code: "DUPLICATE_TIMESTAMP_SLUG",
              canonicalSlug: cleanSlug,
            });
          }
          contentData.slug = cleanSlug;
        }
      }

      const contentType = contentData.type || existing?.type || "";
      const isLessonUpdate = contentType === "lesson" || (existing?.type === "lesson" && !contentData.type);
      if (isLessonUpdate && contentData.title && !contentData.forcePublish) {
        try {
          const { validateLessonTitle } = await import("./title-canonicalizer");
          const titleValidation = validateLessonTitle(contentData.title);
          if (!titleValidation.valid) {
            return res.status(422).json({
              error: `Title validation failed: ${titleValidation.errors.join("; ")}`,
              suggestions: titleValidation.suggestions,
              code: "LESSON_TITLE_INVALID",
            });
          }
        } catch (validationErr: any) {
          console.warn("[TitleValidation] Error during title validation:", validationErr.message);
        }
      }

      const isPublishing = contentData.status === "published" && existing?.status !== "published";
      const isUpdatingPublished = contentData.status === "published" && existing?.status === "published";

      if ((isPublishing || isUpdatingPublished) && !contentData.forcePublish) {
        const pubTitle = contentData.title || existing?.title || "";
        const pubSlug = contentData.slug || existing?.slug || "";
        if (!pubTitle || pubTitle.trim().length === 0) {
          return res.status(422).json({ error: "Cannot publish: title is required.", code: "MISSING_TITLE" });
        }
        if (!pubSlug || pubSlug.trim().length === 0) {
          return res.status(422).json({ error: "Cannot publish: slug is required.", code: "MISSING_SLUG" });
        }

        const pubContent = contentData.content || contentData.body || existing?.content;
        const contentStr = typeof pubContent === "string" ? pubContent : JSON.stringify(pubContent || "[]");
        let parsedOk = true;
        let blockCount = 0;
        try {
          const parsed = JSON.parse(contentStr);
          if (Array.isArray(parsed)) blockCount = parsed.length;
        } catch { parsedOk = false; }

        if (!parsedOk) {
          return res.status(422).json({ error: "Cannot publish: content JSON is malformed.", code: "MALFORMED_CONTENT" });
        }
        if (contentStr.length < 100 || blockCount < 1) {
          return res.status(422).json({ error: "Cannot publish: content is too short or empty. Add substantive content before publishing.", code: "CONTENT_TOO_SHORT" });
        }

        const pubTier = contentData.tier || existing?.tier || "";
        const isLessonType = contentType.includes("lesson") || contentType === "" || !contentType;
        if (isLessonType && pubTier) {
          const { validateTierMessaging } = await import("../shared/tier-messaging");
          const valTitle = contentData.title || existing?.title || "";
          const valSummary = contentData.summary || existing?.summary || "";
          const tierValidation = validateTierMessaging(pubTier, valTitle, valSummary);
          if (!tierValidation.valid) {
            return res.status(422).json({
              error: `Cannot publish: ${tierValidation.error}`,
              code: "TIER_MESSAGING_MISMATCH",
            });
          }

          const REQUIRED_SECTIONS: Record<string, string[]> = {
            np: ["pathophysiology", "assessment", "diagnostic", "management", "pharmaco"],
            rn: ["pathophysiology", "assessment", "nursing"],
            rpn: ["assessment", "nursing"],
          };
          const requiredSections = REQUIRED_SECTIONS[pubTier];
          if (requiredSections && requiredSections.length > 0) {
            const contentLower = contentStr.toLowerCase();
            const missingSections = requiredSections.filter(s => !contentLower.includes(s));
            if (missingSections.length > 0) {
              return res.status(422).json({
                error: `Cannot publish: ${pubTier.toUpperCase()} tier lesson is missing required sections: ${missingSections.join(", ")}. Add these sections before publishing.`,
                code: "MISSING_REQUIRED_SECTIONS",
              });
            }
          }

        }
      }

      const isBlogType = contentType.includes("blog");
      if (isBlogType && (isPublishing || isUpdatingPublished) && !contentData.forcePublish) {
        const blogMinWords = parseInt(process.env.BLOG_MIN_WORDS || "1500", 10);
        const bodyText = extractTextFromContent(contentData.body || contentData.content || existing?.content);
        const wc = countWords(bodyText);
        if (wc < blogMinWords) {
          return res.status(422).json({
            error: `Blog post has ${wc} words, minimum ${blogMinWords} required for publishing. Save as draft or use forcePublish to bypass.`,
            wordCount: wc,
            minimum: blogMinWords,
            code: "POST_TOO_SHORT",
          });
        }
      }

      const isLessonType = (contentData.type || existing?.type || "") === "lesson";
      const isLessonPublishing = contentData.status === "published";
      if (isLessonType && isLessonPublishing && !contentData.forcePublish) {
        const lessonTitle = contentData.title || existing?.title || "";
        const lessonSlug = contentData.slug || existing?.slug || "";
        if (!lessonTitle) {
          return res.status(422).json({ error: "Lesson title is required for publishing.", code: "LESSON_MISSING_TITLE" });
        }
        if (!lessonSlug) {
          return res.status(422).json({ error: "Lesson slug is required for publishing.", code: "LESSON_MISSING_SLUG" });
        }
        const lessonMinWords = parseInt(process.env.LESSON_MIN_WORDS || "100", 10);
        const lessonBodyText = extractTextFromContent(contentData.body || contentData.content || existing?.content);
        const lessonWc = countWords(lessonBodyText);
        if (lessonWc < lessonMinWords) {
          return res.status(422).json({
            error: `Lesson has ${lessonWc} words, minimum ${lessonMinWords} required for publishing. Save as draft or use forcePublish to bypass.`,
            wordCount: lessonWc,
            minimum: lessonMinWords,
            code: "LESSON_TOO_SHORT",
          });
        }
      }

      if (isPublishing && !contentData.forcePublish) {
        try {
          const requiredFields = ["title", "summary"];
          const translationCheck = await checkTranslationCompleteness("content_item", routeParamString(req.params.id), requiredFields);
          if (!translationCheck.complete) {
            const incompleteLangs = Object.entries(translationCheck.languages)
              .filter(([_, info]) => info.status !== "complete")
              .map(([lang, info]) => `${lang}: ${info.status} (missing: ${info.missingFields.join(", ") || "none"}, stale: ${info.staleFields.join(", ") || "none"})`)
              .join("; ");
            return res.status(422).json({
              error: `Cannot publish: translations are incomplete for some languages. Use forcePublish to override. Incomplete: ${incompleteLangs}`,
              code: "TRANSLATION_INCOMPLETE",
              translationStatus: translationCheck.languages,
              canOverride: true,
            });
          }
        } catch (translationErr: any) {
          console.warn("[TranslationLock] Error checking translation completeness:", translationErr.message);
        }
      }

      if (existing) {
        const updatedSourceFields: Record<string, string | null | undefined> = {};
        if (contentData.title !== undefined && contentData.title !== existing.title) {
          updatedSourceFields.title = contentData.title;
        }
        if (contentData.summary !== undefined && contentData.summary !== existing.summary) {
          updatedSourceFields.summary = contentData.summary;
        }
        if (contentData.seoTitle !== undefined && contentData.seoTitle !== (existing as any).seoTitle) {
          updatedSourceFields.seoTitle = contentData.seoTitle;
        }
        if (contentData.seoDescription !== undefined && contentData.seoDescription !== (existing as any).seoDescription) {
          updatedSourceFields.seoDescription = contentData.seoDescription;
        }
        const contentStr = contentData.content !== undefined ? contentData.content : contentData.body;
        const existingContent = existing.content || (existing as any).body;
        if (contentStr !== undefined && JSON.stringify(contentStr) !== JSON.stringify(existingContent)) {
          updatedSourceFields.content = typeof contentStr === "string" ? contentStr : JSON.stringify(contentStr);
        }

        if (Object.keys(updatedSourceFields).length > 0) {
          const markedCount = await markTranslationsOutdated("content_item", routeParamString(req.params.id), updatedSourceFields);
          if (markedCount > 0) {
            console.log(`[i18n-versioning] Marked ${markedCount} translations as outdated for content ${routeParamString(req.params.id)}`);
          }
          try {
            await incrementSourceVersionAndMarkStale("content_items", routeParamString(req.params.id));
          } catch (svErr: any) {
            console.error("[i18n-versioning] source_version increment error:", svErr.message);
          }
        }
      }

      const updateContentType = contentType === "lesson" ? "lesson" : contentType.includes("blog") ? "blog" : contentType === "flashcard-set" ? "flashcard" : contentType;
      const { repairedData: repairedContentData, repairs: updateRepairs } = autoRepairContent(updateContentType, contentData);

      const isPublishAttempt = repairedContentData.status === "published" && existing?.status !== "published";
      if (isPublishAttempt) {
        const mergedForValidation = { ...existing, ...repairedContentData };
        const validation = validateForPublish(updateContentType, mergedForValidation);
        if (!validation.valid) {
          return res.status(422).json({
            error: "Content validation failed. Fix critical errors before publishing.",
            code: "VALIDATION_FAILED",
            validation,
            forcePublishBypassed: !!repairedContentData.forcePublish,
          });
        }
      }

      const item = await storage.updateContentItem(routeParamString(req.params.id), repairedContentData);
      if (repairedContentData.status === "published" || existing?.status === "published") {
        heroStatsCache = null;
      }

      if (updateRepairs.length > 0) {
        await logAutoRepairs(updateContentType, routeParamString(req.params.id), updateRepairs);
      }

      cacheInvalidate("lessons:");
      cacheInvalidate("flashcard-sets:");
      cacheInvalidate("exams:");

      if (contentData.status === "published") {
        try {
          const { createVersionOnPublish } = await import("./content-version-service");
          await createVersionOnPublish(routeParamString(req.params.id), contentType || "content_item", item, {
            tier: item.tier || undefined,
            region: item.regionScope || undefined,
            createdBy: (admin as any)?.id || (admin as any)?.username,
          });
        } catch (vErr: any) {
          console.error("[ContentVersion] Error during publish version creation:", vErr.message);
        }
      }

      await logAudit(req, admin, "content", routeParamString(req.params.id), "update",
        existing ? { title: existing.title, status: existing.status } : null,
        { title: item.title, status: item.status, autoRepairs: updateRepairs.length }
      );

      if (item.status === "published") {
        try {
          const { generateRenderPayloads } = await import("./content-failover");
          await generateRenderPayloads(item.id);
          await createContentSnapshot(item.id, updateContentType, item, "publish");
        } catch (payloadErr: any) {
          console.error("[Content] Render payload generation error:", payloadErr.message);
        }
      }

      res.json(item);
    } catch (e: any) {
      res.status(400).json({ error: e.message });
    }
  });

