  app.post("/api/admin/qbank/bulk-publish", async (req, res) => {
    try {
      const admin = await requireAdmin(req, res);
      if (!admin) return;
      const { ids } = req.body;
      if (!ids?.length) return res.status(400).json({ error: "ids required" });

      const { isValidRationale } = await import("./rationale-remediation");
      const checkResult = await pool.query(
        `SELECT id, rationale FROM exam_questions WHERE id = ANY($1) AND status != 'published'`,
        [ids]
      );
      const blocked: string[] = [];
      const eligible: string[] = [];
      for (const row of checkResult.rows) {
        if (!isValidRationale(row.rationale)) {
          blocked.push(row.id);
        } else {
          eligible.push(row.id);
        }
      }

      let publishedCount = 0;
      if (eligible.length > 0) {
        const result = await pool.query(
          `UPDATE exam_questions SET status = 'published', published_at = COALESCE(published_at, NOW()), updated_at = NOW()
           WHERE id = ANY($1) AND status != 'published'`,
          [eligible]
        );
        publishedCount = result.rowCount || 0;

        try {
          const { createVersionOnPublish } = await import("./content-version-service");
          const publishedRows = await pool.query(
            `SELECT id, tier, exam, question_type, status, stem, options, correct_answer, rationale, difficulty, tags, body_system, topic, subtopic, region_scope, career_type FROM exam_questions WHERE id = ANY($1) LIMIT 200`,
            [eligible.slice(0, 200)]
          );
          for (const q of publishedRows.rows) {
            await createVersionOnPublish(q.id, "exam_question", q, {
              tier: q.tier,
              createdBy: (admin as any)?.id || (admin as any)?.username,
            });
          }
        } catch (vErr: any) {
          console.error("[ContentVersion] Bulk publish version error:", vErr.message);
        }
      }

      heroStatsCache = null;
      res.json({
        published: publishedCount,
        blocked: blocked.length,
        blockedIds: blocked,
        blockedReason: blocked.length > 0 ? "Questions with missing or invalid rationales cannot be published" : undefined,
      });
    } catch (e: any) {
      res.status(500).json({ error: e.message });
    }
  });

