  app.post("/api/admin/flashcard-bank/bulk-publish", async (req, res) => {
    try {
      const admin = await requireAdmin(req, res);
      if (!admin) return;
      const { ids, forcePublish } = req.body;
      if (!ids?.length) return res.status(400).json({ error: "ids required" });

      {
        const cardsResult = await pool.query(
          `SELECT id, front, back, tier, tags_json as tags FROM flashcard_bank WHERE id = ANY($1)`,
          [ids]
        );
        const validationErrors: { id: string; errors: ValidationError[] }[] = [];
        for (const card of cardsResult.rows) {
          const validation = validateForPublish("flashcard", card);
          if (!validation.valid) {
            validationErrors.push({ id: card.id, errors: validation.errors });
          }
        }
        if (validationErrors.length > 0) {
          return res.status(422).json({
            error: `${validationErrors.length} flashcard(s) failed validation.`,
            code: "VALIDATION_FAILED",
            failedCards: validationErrors,
            forcePublishBypassed: !!forcePublish,
          });
        }
      }

      const result = await pool.query(
        `UPDATE flashcard_bank SET status = 'published', updated_at = NOW()
         WHERE id = ANY($1) AND status != 'published'`,
        [ids]
      );

      try {
        const { createVersionOnPublish } = await import("./content-version-service");
        const publishedRows = await pool.query(
          `SELECT * FROM flashcard_bank WHERE id = ANY($1) AND status = 'published' LIMIT 200`,
          [ids]
        );
        for (const fc of publishedRows.rows) {
          await createVersionOnPublish(fc.id, "flashcard", fc, {
            tier: fc.tier,
            createdBy: (admin as any)?.id || (admin as any)?.username,
          });
        }
      } catch (vErr: any) {
        console.error("[ContentVersion] Flashcard bulk publish version error:", vErr.message);
      }

      res.json({ published: result.rowCount });
    } catch (e: any) {
      res.status(500).json({ error: e.message });
    }
  });

