  app.get("/api/admin/cat-analytics", async (req, res) => {
    try {
      const admin = await requireAdmin(req, res);
      if (!admin) return;
      const sessions = await pool.query(`SELECT final_ability, confidence_interval, stability_index, early_stop, question_count, created_at FROM user_ability_sessions ORDER BY created_at DESC LIMIT 500`);
      const adjustments = await pool.query(`SELECT * FROM difficulty_adjustment_log ORDER BY created_at DESC LIMIT 50`);
      const abilityDistribution = [0, 0, 0, 0, 0, 0, 0];
      sessions.rows.forEach((s: any) => {
        const bucket = Math.min(6, Math.max(0, Math.floor((s.final_ability + 9) / 3)));
        abilityDistribution[bucket]++;
      });
      const earlyStopCount = sessions.rows.filter((s: any) => s.early_stop).length;

      let poolHealth: any = null;
      try {
        const { buildCATPool } = await import("./cat-session-api");
        const tiers = ["rpn", "rn", "np"];
        const tierHealth: Record<string, any> = {};
        for (const t of tiers) {
          const { diagnostics } = await buildCATPool(t);
          tierHealth[t] = diagnostics;
        }
        poolHealth = tierHealth;
      } catch (poolErr: any) {
        console.error("[CATAnalytics] Pool health check error:", poolErr.message);
      }

      res.json({ totalSessions: sessions.rows.length, abilityDistribution, earlyStopRate: sessions.rows.length > 0 ? (earlyStopCount / sessions.rows.length * 100).toFixed(1) : 0, avgQuestionCount: sessions.rows.length > 0 ? Math.round(sessions.rows.reduce((a: number, s: any) => a + s.question_count, 0) / sessions.rows.length) : 0, recentSessions: sessions.rows.slice(0, 20), adjustmentLog: adjustments.rows, poolHealth });
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  app.post("/api/admin/cat-pool-normalize", async (req, res) => {
    try {
      const admin = await requireAdmin(req, res);
      if (!admin) return;

      const dryRun = req.body?.dryRun !== false;
      const changes: any[] = [];

      const nullDiffResult = await pool.query(
        `SELECT id, tier, stem FROM exam_questions WHERE status = 'published' AND difficulty IS NULL`
      );
      for (const q of nullDiffResult.rows) {
        changes.push({ id: q.id, tier: q.tier, action: "set_difficulty_3", reason: "published question with null difficulty" });
        if (!dryRun) {
          await pool.query(`UPDATE exam_questions SET difficulty = 3 WHERE id = $1`, [q.id]);
        }
      }

      const eligibleResult = await pool.query(
        `SELECT id, tier, stem, options, correct_answer, difficulty, is_adaptive_eligible
         FROM exam_questions
         WHERE status = 'published'
         AND (is_adaptive_eligible IS NULL OR is_adaptive_eligible = false)
         AND stem IS NOT NULL AND LENGTH(TRIM(stem)) >= 10
         AND correct_answer IS NOT NULL
         AND difficulty IS NOT NULL`
      );
      for (const q of eligibleResult.rows) {
        let opts = q.options;
        if (typeof opts === "string") {
          try { opts = JSON.parse(opts); } catch { continue; }
        }
        if (!Array.isArray(opts) || opts.length < 4) continue;

        changes.push({ id: q.id, tier: q.tier, action: "set_adaptive_eligible", reason: "meets minimum CAT criteria" });
        if (!dryRun) {
          await pool.query(`UPDATE exam_questions SET is_adaptive_eligible = true WHERE id = $1`, [q.id]);
        }
      }

      console.log(`[CATNormalize] dryRun=${dryRun} totalChanges=${changes.length} difficultyFixes=${nullDiffResult.rows.length} eligibilityFixes=${changes.filter(c => c.action === "set_adaptive_eligible").length}`);

      res.json({
        dryRun,
        totalChanges: changes.length,
        difficultyFixes: nullDiffResult.rows.length,
        eligibilityFixes: changes.filter(c => c.action === "set_adaptive_eligible").length,
        changes: changes.slice(0, 200),
      });
    } catch (e: any) {
      console.error("[CATNormalize] Error:", e.message);
      res.status(500).json({ error: e.message });
    }
  });

  // ====== BLUEPRINT COVERAGE + DIFFICULTY DISTRIBUTION ======
  app.get("/api/admin/blueprint-coverage", async (req, res) => {
    try {
      const admin = await requireAdmin(req, res);
      if (!admin) return;
      const blueprints = await pool.query(`SELECT * FROM exam_blueprints WHERE active = true`);
      const questionCounts = await pool.query(
        `SELECT exam, body_system, COUNT(*) as count FROM exam_questions WHERE status = 'published' GROUP BY exam, body_system`
      );
      const qMap = new Map<string, Map<string, number>>();
      for (const row of questionCounts.rows) {
        if (!qMap.has(row.exam)) qMap.set(row.exam, new Map());
        qMap.get(row.exam)!.set((row.body_system || "").toLowerCase(), Number(row.count));
      }

      const coverage = [];
      for (const bp of blueprints.rows) {
        const domains = Array.isArray(bp.domains) ? bp.domains : [];
        const examQuestions = qMap.get(bp.exam_code) || new Map();
        const totalExamQuestions = Array.from(examQuestions.values()).reduce((a, b) => a + b, 0);

        const domainCoverage = domains.map((d: any) => {
          const domainName = d.name || d.domain || "Unknown";
          const targetWeight = d.weight || d.percentage || 0;
          const questionCount = examQuestions.get(domainName.toLowerCase()) || 0;
          const currentPercent = totalExamQuestions > 0 ? Math.round((questionCount / totalExamQuestions) * 100) : 0;
          const targetQuestions = Math.ceil((targetWeight / 100) * (bp.total_questions || 100));
          const gap = Math.max(0, targetQuestions - questionCount);
          let status = "adequate";
          if (questionCount === 0) status = "empty";
          else if (currentPercent < targetWeight * 0.5) status = "critical";
          else if (currentPercent < targetWeight * 0.8) status = "low";

          return { domain: domainName, targetWeight, questionCount, currentPercent, status, recommendedToAdd: gap };
        });
        coverage.push({ examCode: bp.exam_code, examName: bp.exam_name, totalQuestions: bp.total_questions, actualQuestionCount: totalExamQuestions, domains: domainCoverage });
      }
      res.json(coverage);
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

