  app.post("/api/admin/qbank-drafts/:id/generate", async (req, res) => {
    const admin = await requireAdmin(req, res);
    if (!admin) return;
    try {
      const draft = await storage.getQbankDraft(req.params.id);
      if (!draft) return res.status(404).json({ error: "Not found" });

      await storage.updateQbankDraft(draft.id, { status: "generating" } as any);

      const CHUNK_SIZE = 25;
      const requested = draft.requestedCount;
      const maxPasses = Math.ceil(requested / CHUNK_SIZE) + 5;
      const allQuestions: any[] = [];
      const seenHashes = new Set<string>();
      const errors: string[] = [];

      const hashQ = (q: any) => {
        const s = ((q.scenario || "") + (q.stem || "")).toLowerCase().replace(/\s+/g, " ").trim();
        let h = 0;
        for (let i = 0; i < s.length; i++) { h = ((h << 5) - h + s.charCodeAt(i)) | 0; }
        return h.toString(36);
      };

      const VALID_CATS = ["Safe and Effective Care Environment", "Health Promotion and Maintenance", "Psychosocial Integrity", "Physiological Integrity"];
      const VALID_TYPES = ["MCQ", "SATA", "PRIORITY", "DELEGATION"];

      const validateQ = (q: any): string | null => {
        if (!q.stem || !q.options || !q.correctAnswer) return "missing required fields";
        const t = (q.type || "MCQ").toUpperCase();
        if (!VALID_TYPES.includes(t)) return `invalid type: ${t}`;
        if (!VALID_CATS.some(c => (q.category || "").includes(c.split(" ")[0]))) {
          q.category = VALID_CATS[Math.floor(Math.random() * VALID_CATS.length)];
        }
        if (t === "SATA") {
          if (q.options.length < 6) return "SATA needs 6+ options";
          if (!Array.isArray(q.correctAnswer) || q.correctAnswer.length < 2) return "SATA needs array of 2+ answers";
        } else {
          if (q.options.length < 4) return "needs 4 options";
          if (Array.isArray(q.correctAnswer)) q.correctAnswer = q.correctAnswer[0];
        }
        return null;
      };

      const contextLabel = draft.canadianContext ? "Canadian REx-PN" : "US NCLEX";
      const topicLabel = draft.mixedBlueprint ? "mixed clinical blueprint" : draft.topic;

      const distJson = (draft.distributionJson || {}) as any;
      const topicMix: { topic: string; weightPercent: number }[] = distJson.topicMix || [];
      const typeMix: { type: string; weightPercent: number }[] = distJson.typeMix || [];

      let topicInstruction = "";
      if (topicMix.length > 0) {
        const topicLines = topicMix.map(t => `  - ${t.topic}: ${t.weightPercent}% (~${Math.round(requested * t.weightPercent / 100)} questions)`).join("\n");
        topicInstruction = `\nDistribute questions across these clinical topics:\n${topicLines}\nEach question must include a topicTag field matching one of these topics exactly.`;
      }

      let typeInstruction = "";
      if (typeMix.length > 0) {
        const typeLines = typeMix.map(t => `  - ${t.type}: ${t.weightPercent}%`).join("\n");
        typeInstruction = `\nQuestion type distribution:\n${typeLines}`;
      }

      for (let pass = 0; pass < maxPasses && allQuestions.length < requested; pass++) {
        const remaining = requested - allQuestions.length;
        const batchSize = Math.min(CHUNK_SIZE, remaining);
        console.log(`[QBank ${draft.id}] Chunk ${pass + 1}: generating ${batchSize}, have ${allQuestions.length}/${requested}`);

        let chunkTopicHint = "";
        if (topicMix.length > 0 && allQuestions.length > 0) {
          const currentTopicCounts: Record<string, number> = {};
          for (const q of allQuestions) {
            const tag = q.topicTag || q.topic || "Unknown";
            currentTopicCounts[tag] = (currentTopicCounts[tag] || 0) + 1;
          }
          const deficits: string[] = [];
          for (const tm of topicMix) {
            const target = Math.round(requested * tm.weightPercent / 100);
            const actual = currentTopicCounts[tm.topic] || 0;
            if (actual < target) {
              deficits.push(`${tm.topic} (need ${target - actual} more)`);
            }
          }
          if (deficits.length > 0) {
            chunkTopicHint = ` Focus on these deficit topics: ${deficits.join(", ")}.`;
          }
        }

        try {
          const openai = (await import("./openai-client")).getOpenAIClient();
          const resp = await openai.chat.completions.create({
            model: "gpt-4o",
            temperature: 0.85,
            max_tokens: 16000,
            response_format: { type: "json_object" },
            messages: [
              {
                role: "system",
                content: `You are a ${contextLabel} exam item writer. Generate exactly ${batchSize} unique clinical nursing questions in JSON format. Output: {"questions":[...]}. Each question must have: id (number), category (one of: ${VALID_CATS.join(", ")}), type (MCQ or SATA or PRIORITY or DELEGATION), topicTag (clinical topic string), scenario (2-3 sentence clinical vignette), stem (the question), options (array of strings, A-D for MCQ/PRIORITY/DELEGATION, A-H for SATA), correctAnswer (single letter for MCQ/PRIORITY/DELEGATION, array of letters for SATA), rationaleCorrect (why correct answer is right), rationaleIncorrect (array of strings explaining why each wrong option is wrong), clinicalPearl (key takeaway). Difficulty: ${draft.difficulty}. Every scenario must be unique.${topicInstruction}${typeInstruction}`
              },
              {
                role: "user",
                content: `Generate ${batchSize} ${contextLabel} practice questions on: ${topicLabel}. Starting from question ID ${allQuestions.length + 1}. Ensure each question has a unique clinical scenario. ${draft.canadianContext ? "Use Canadian nursing context, units (mmol/L, celsius), and healthcare system references." : ""}${chunkTopicHint}`
              }
            ]
          });

          const raw = resp.choices[0]?.message?.content || "{}";
          const parsed = JSON.parse(raw);
          const qs = parsed.questions || [];

          for (const q of qs) {
            const h = hashQ(q);
            if (seenHashes.has(h)) continue;
            const err = validateQ(q);
            if (err) { errors.push(`Q${q.id}: ${err}`); continue; }
            seenHashes.add(h);
            q.id = allQuestions.length + 1;
            q.type = (q.type || "MCQ").toUpperCase();
            if (!q.topicTag && topicMix.length > 0) {
              q.topicTag = topicMix[allQuestions.length % topicMix.length].topic;
            }
            allQuestions.push(q);
            if (allQuestions.length >= requested) break;
          }
        } catch (chunkErr: any) {
          errors.push(`Chunk ${pass + 1} error: ${chunkErr.message}`);
        }
      }

      const byType: Record<string, number> = {};
      const byCategory: Record<string, number> = {};
      const byTopic: Record<string, number> = {};
      for (const q of allQuestions) {
        byType[q.type] = (byType[q.type] || 0) + 1;
        const catKey = (q.category || "Unknown").split(" ").slice(0, 3).join(" ");
        byCategory[catKey] = (byCategory[catKey] || 0) + 1;
        const topicKey = q.topicTag || q.topic || "Unknown";
        byTopic[topicKey] = (byTopic[topicKey] || 0) + 1;
      }

      let topicDistribution: any = null;
      if (topicMix.length > 0) {
        topicDistribution = topicMix.map(tm => {
          const actual = byTopic[tm.topic] || 0;
          const target = Math.round(requested * tm.weightPercent / 100);
          const actualPct = allQuestions.length > 0 ? Math.round((actual / allQuestions.length) * 100) : 0;
          const diff = Math.abs(actualPct - tm.weightPercent);
          return {
            topic: tm.topic,
            requestedPct: tm.weightPercent,
            actualPct,
            targetCount: target,
            actualCount: actual,
            withinTolerance: diff <= 2 || Math.abs(actual - target) <= 2,
          };
        });
      }

      const audit = {
        ok: allQuestions.length === requested,
        requestedCount: requested,
        generatedCount: allQuestions.length,
        countMatch: allQuestions.length === requested,
        byType,
        byCategory,
        byTopic,
        topicDistribution,
        errors,
        timestamp: new Date().toISOString(),
      };

      await storage.updateQbankDraft(draft.id, {
        questionsJson: allQuestions,
        auditJson: audit,
        status: audit.ok ? "validated" : "partial",
      } as any);

      res.json({ audit, questionCount: allQuestions.length });
    } catch (e: any) {
      await storage.updateQbankDraft(req.params.id, { status: "error" } as any).catch(() => {});
      res.status(500).json({ error: e.message });
    }
  });

  app.post("/api/admin/qbank-drafts/:id/complete-missing", async (req, res) => {
    const admin = await requireAdmin(req, res);
    if (!admin) return;
    try {
      const draft = await storage.getQbankDraft(req.params.id);
      if (!draft) return res.status(404).json({ error: "Not found" });
      const existing: any[] = (draft.questionsJson as any[]) || [];
      const requested = draft.requestedCount;
      if (existing.length >= requested) return res.json({ message: "Already complete", count: existing.length });

      const missing = requested - existing.length;
      await storage.updateQbankDraft(draft.id, { status: "completing" } as any);

      const seenHashes = new Set<string>();
      const hashQ = (q: any) => {
        const s = ((q.scenario || "") + (q.stem || "")).toLowerCase().replace(/\s+/g, " ").trim();
        let h = 0;
        for (let i = 0; i < s.length; i++) { h = ((h << 5) - h + s.charCodeAt(i)) | 0; }
        return h.toString(36);
      };
      for (const q of existing) seenHashes.add(hashQ(q));

      const VALID_CATS = ["Safe and Effective Care Environment", "Health Promotion and Maintenance", "Psychosocial Integrity", "Physiological Integrity"];
      const VALID_TYPES = ["MCQ", "SATA", "PRIORITY", "DELEGATION"];
      const contextLabel = draft.canadianContext ? "Canadian REx-PN" : "US NCLEX";
      const topicLabel = draft.mixedBlueprint ? "mixed clinical blueprint" : draft.topic;
      const newQs: any[] = [];
      const errors: string[] = [];

      for (let pass = 0; pass < missing + 5 && newQs.length < missing; pass++) {
        const batchSize = Math.min(25, missing - newQs.length);
        try {
          const openai = (await import("./openai-client")).getOpenAIClient();
          const resp = await openai.chat.completions.create({
            model: "gpt-4o", temperature: 0.9, max_tokens: 16000,
            response_format: { type: "json_object" },
            messages: [
              { role: "system", content: `Generate exactly ${batchSize} unique ${contextLabel} nursing questions in JSON. Output: {"questions":[...]}. Categories: ${VALID_CATS.join(", ")}. Types: MCQ/SATA/PRIORITY/DELEGATION. Each needs: id, category, type, scenario, stem, options, correctAnswer, rationaleCorrect, rationaleIncorrect, clinicalPearl.` },
              { role: "user", content: `Generate ${batchSize} questions on ${topicLabel}. Starting ID ${existing.length + newQs.length + 1}. Must be completely different from previous questions.` }
            ]
          });
          const parsed = JSON.parse(resp.choices[0]?.message?.content || "{}");
          for (const q of (parsed.questions || [])) {
            const h = hashQ(q);
            if (seenHashes.has(h)) continue;
            seenHashes.add(h);
            q.id = existing.length + newQs.length + 1;
            q.type = (q.type || "MCQ").toUpperCase();
            if (!VALID_TYPES.includes(q.type)) continue;
            newQs.push(q);
            if (newQs.length >= missing) break;
          }
        } catch (err: any) {
          errors.push(err.message);
        }
      }

      const merged = [...existing, ...newQs];
      const byType: Record<string, number> = {};
      const byCategory: Record<string, number> = {};
      for (const q of merged) {
        byType[q.type] = (byType[q.type] || 0) + 1;
        const catKey = (q.category || "").split(" ").slice(0, 3).join(" ");
        byCategory[catKey] = (byCategory[catKey] || 0) + 1;
      }

      const audit = {
        ok: merged.length === requested,
        requestedCount: requested,
        generatedCount: merged.length,
        countMatch: merged.length === requested,
        byType, byCategory, errors,
        timestamp: new Date().toISOString(),
      };

      await storage.updateQbankDraft(draft.id, {
        questionsJson: merged,
        auditJson: audit,
        status: audit.ok ? "validated" : "partial",
      } as any);

      res.json({ audit, added: newQs.length, total: merged.length });
    } catch (e: any) {
      res.status(500).json({ error: e.message });
    }
  });

  app.post("/api/admin/qbank-drafts/:id/publish", async (req, res) => {
    const admin = await requireAdmin(req, res);
    if (!admin) return;
    try {
      const draft = await storage.getQbankDraft(req.params.id);
      if (!draft) return res.status(404).json({ error: "Not found" });
      const audit = draft.auditJson as any;
      if (!audit?.ok) return res.status(400).json({ error: "Cannot publish: audit not passed. generatedCount must equal requestedCount." });
      const questions = (draft.questionsJson as any[]) || [];
      if (questions.length !== draft.requestedCount) return res.status(400).json({ error: "Question count mismatch" });

      const editions = (draft.editionsJson as any) || { questionsOnly: true, studyEdition: false };
      const baseSlug = draft.slug;
      const results: any = {};

      if (editions.questionsOnly) {
        const product = await storage.createDigitalProduct({
          title: draft.title,
          slug: baseSlug,
          description: `${draft.requestedCount} ${draft.exam.toUpperCase()} practice questions with answer key. ${draft.canadianContext ? "Canadian-focused." : ""} Exam-style formatting, continuous numbering, printable.`,
          shortDescription: `${draft.requestedCount} practice questions + answer key`,
          price: draft.price || 1499,
          category: "qbank",
          tierTarget: "all",
          examTarget: draft.exam,
          featured: false,
          isActive: true,
          questionCount: draft.requestedCount || 0,
        });
        await storage.updateQbankDraft(draft.id, { publishedProductId: product.id } as any);
        results.questionsOnly = product;
      }

      if (editions.studyEdition) {
        const studyProduct = await storage.createDigitalProduct({
          title: `${draft.title} - Study Edition`,
          slug: `${baseSlug}-study-edition`,
          description: `${draft.requestedCount} ${draft.exam.toUpperCase()} practice questions with full rationales, clinical pearls, and answer explanations. ${draft.canadianContext ? "Canadian-focused." : ""} Premium study resource.`,
          shortDescription: `${draft.requestedCount} questions + rationales + clinical pearls`,
          price: draft.studyEditionPrice || 2499,
          category: "qbank",
          tierTarget: "all",
          examTarget: draft.exam,
          featured: false,
          isActive: true,
          questionCount: draft.requestedCount || 0,
        });
        await storage.updateQbankDraft(draft.id, { publishedStudyProductId: studyProduct.id } as any);
        results.studyEdition = studyProduct;
      }

      await storage.updateQbankDraft(draft.id, { status: "published" } as any);
      res.json({ published: true, products: results });
    } catch (e: any) {
      res.status(500).json({ error: e.message });
    }
  });

  app.post("/api/admin/qbank-drafts/:id/generate-forms", async (req, res) => {
    const admin = await requireAdmin(req, res);
    if (!admin) return;
    try {
      const draft = await storage.getQbankDraft(req.params.id);
      if (!draft) return res.status(404).json({ error: "Not found" });
      const questions = (draft.questionsJson as any[]) || [];
      if (questions.length < 10) return res.status(400).json({ error: "Master bank needs at least 10 questions" });

      const { formCount = 1, formSize = 90, seed, includeRationales = false, topicMix: reqTopicMix, difficultyTarget } = req.body;
      const formSeed = seed || Date.now();

      function seededRandom(s: number) {
        let x = s;
        return () => { x = (x * 1103515245 + 12345) & 0x7fffffff; return x / 0x7fffffff; };
      }

      const forms: any[] = [];
      const usedIds = new Set<number>();

      for (let f = 0; f < Math.min(formCount, 3); f++) {
        const rng = seededRandom(formSeed + f * 1000);
        let available = questions.filter(q => !usedIds.has(q.id) || formCount === 1);

        if (difficultyTarget && difficultyTarget !== "mixed") {
          const diffFiltered = available.filter(q => (q.difficulty || "medium") === difficultyTarget);
          if (diffFiltered.length >= formSize) available = diffFiltered;
        }

        let formQs: any[] = [];
        if (reqTopicMix && Array.isArray(reqTopicMix) && reqTopicMix.length > 0) {
          const byTopicPool: Record<string, any[]> = {};
          for (const q of available) {
            const tag = q.topicTag || q.topic || "General";
            if (!byTopicPool[tag]) byTopicPool[tag] = [];
            byTopicPool[tag].push(q);
          }
          for (const tm of reqTopicMix) {
            const count = Math.round(formSize * tm.weightPercent / 100);
            const pool = byTopicPool[tm.topic] || [];
            const shuffledPool = [...pool].sort(() => rng() - 0.5);
            formQs.push(...shuffledPool.slice(0, count));
          }
          if (formQs.length < formSize) {
            const usedInForm = new Set(formQs.map(q => q.id));
            const remaining = available.filter(q => !usedInForm.has(q.id));
            const shuffledRemaining = [...remaining].sort(() => rng() - 0.5);
            formQs.push(...shuffledRemaining.slice(0, formSize - formQs.length));
          }
          formQs = formQs.sort(() => rng() - 0.5).slice(0, formSize);
        } else {
          const shuffled = [...available].sort(() => rng() - 0.5);
          formQs = shuffled.slice(0, Math.min(formSize, shuffled.length));
        }
        formQs.forEach(q => usedIds.add(q.id));

        const formLabel = String.fromCharCode(65 + f);
        const answerKey = formQs.map((q: any, i: number) => ({
          number: i + 1,
          correctAnswer: q.correctAnswer,
          type: q.type,
          topic: q.topicTag || q.topic || "",
        }));

        const formData: any = {
          formId: formLabel,
          seed: formSeed + f * 1000,
          questionCount: formQs.length,
          questionIds: formQs.map((q: any) => q.id),
          questions: formQs.map((q: any, i: number) => ({ ...q, id: i + 1 })),
          answerKey,
        };

        if (includeRationales) {
          formData.rationales = formQs.map((q: any, i: number) => ({
            number: i + 1,
            rationaleCorrect: q.rationaleCorrect || "",
            rationaleIncorrect: q.rationaleIncorrect || [],
            clinicalPearl: q.clinicalPearl || "",
          }));
        }

        forms.push(formData);
      }

      const updatedDist = { ...(draft.distributionJson as any || {}), forms };
      await storage.updateQbankDraft(draft.id, { distributionJson: updatedDist } as any);

      res.json({ forms: forms.map(f => ({ formId: f.formId, questionCount: f.questionCount, seed: f.seed })), totalForms: forms.length });
    } catch (e: any) {
      res.status(500).json({ error: e.message });
    }
  });

