  app.get("/api/question-bank/exam", requireAnyPaidTier(), async (req: any, res) => {
    try {
      const user = await resolveAuthUser(req);
      if (!user) return res.status(401).json({ error: "Authentication required" });

      const internationalExams = ["NMC-CBT", "AHPRA-RN", "GULF-NURSING"];
      const examFilter = req.query.exam as string;

      if (examFilter && internationalExams.includes(examFilter)) {
        const count = Math.min(parseInt(req.query.count as string) || 25, 100);
        let query = `SELECT id, stem, options, correct_answer, rationale, body_system AS category,
                            CASE WHEN difficulty = 2 THEN 'easy' WHEN difficulty = 3 THEN 'moderate' WHEN difficulty = 4 THEN 'hard' ELSE 'moderate' END AS difficulty,
                            exam, topic
                     FROM exam_questions
                     WHERE exam = $1 AND status = 'published'`;
        const params: any[] = [examFilter];
        let paramIdx = 2;

        if (req.query.category) {
          query += ` AND (body_system ILIKE $${paramIdx} OR topic ILIKE $${paramIdx})`;
          params.push(`%${req.query.category}%`);
          paramIdx++;
        }
        if (req.query.difficulty) {
          const diffMap: Record<string, number> = { easy: 2, moderate: 3, hard: 4, very_hard: 5 };
          const diffVal = diffMap[req.query.difficulty as string];
          if (diffVal) {
            query += ` AND difficulty = $${paramIdx}`;
            params.push(diffVal);
            paramIdx++;
          }
        }

        query += ` ORDER BY RANDOM() LIMIT $${paramIdx}`;
        params.push(count);

        const result = await pool.query(query, params);

        const transformed = result.rows.map((row: any) => {
          let options = row.options;
          if (typeof options === "string") {
            try { options = JSON.parse(options); } catch { options = []; }
          }
          const optArray = Array.isArray(options) ? options : [];
          return {
            id: row.id,
            question: row.stem,
            optionA: optArray[0]?.text || optArray[0] || "",
            optionB: optArray[1]?.text || optArray[1] || "",
            optionC: optArray[2]?.text || optArray[2] || "",
            optionD: optArray[3]?.text || optArray[3] || "",
            correctAnswer: (() => {
              let ca = row.correct_answer;
              if (typeof ca === "string") {
                try { ca = JSON.parse(ca); } catch {}
              }
              if (typeof ca === "string") return ca;
              if (typeof ca === "number") return ["A", "B", "C", "D"][ca] || "A";
              if (Array.isArray(ca)) return ["A", "B", "C", "D"][ca[0]] || "A";
              return "A";
            })(),
            rationale: row.rationale || "",
            category: row.category || row.topic || "",
            difficulty: row.difficulty,
            examType: row.exam,
            country: examFilter === "NMC-CBT" ? "GB" : examFilter === "AHPRA-RN" ? "AU" : "AE",
            questionType: "multiple_choice",
            clientNeeds: row.topic || "",
            topic: row.topic || "",
            status: "active",
          };
        });

        return res.json(transformed);
      }

      const gate = resolveQuestionBankLearnerGate(user, false);
      if (gate.kind !== "learner") {
        return res.status(500).json({ error: "Unexpected gate state" });
      }
      if (!gate.scope) return res.status(400).json({ error: "User region not set. Please update your profile." });
      if (gate.contentTiers.length === 0) {
        return res.json([]);
      }
      const count = Math.min(parseInt(req.query.count as string) || 25, 100);
      const filters: any = {
        country: gate.scope.country,
        examType: gate.scope.examType,
        contentTiersIn: gate.contentTiers,
        requireNonNullContentTier: true,
      };
      if (req.query.category) filters.category = req.query.category;
      if (req.query.difficulty) filters.difficulty = req.query.difficulty;
      const questions = await storage.getQuestionBankRandomSubset(filters, count);
      res.json(questions);
    } catch (e: any) {
      res.status(500).json({ error: e.message });
    }
  });

  app.get("/api/question-bank/study", requireAnyPaidTier(), async (req: any, res) => {
    try {
      const user = await resolveAuthUser(req);
      if (!user) return res.status(401).json({ error: "Authentication required" });

      const allowedTiers = allowedNursingFlashcardBankTiersForUser(user.tier || "free");
      if (allowedTiers.length === 0) {
        return res.json([]);
      }

      const count = Math.min(parseInt(req.query.count as string) || 10, 50);
      const category = req.query.category as string;
      const difficulty = req.query.difficulty as string;

      const conditions = ["status = 'published'", "flashcard_enabled = true", "source_type = 'cat_exam'", "options::text != '[]'", "options IS NOT NULL"];
      const params: any[] = [];
      let paramIdx = 1;

      conditions.push(`tier = ANY($${paramIdx++})`);
      params.push(allowedTiers);

      if (category) {
        conditions.push(`(category ILIKE $${paramIdx} OR body_system ILIKE $${paramIdx} OR topic ILIKE $${paramIdx})`);
        params.push(`%${category}%`);
        paramIdx++;
      }
      if (difficulty) {
        const diffMap: Record<string, number[]> = { easy: [1, 2], moderate: [3], hard: [4], very_hard: [5] };
        const levels = diffMap[difficulty] || [3];
        conditions.push(`difficulty = ANY($${paramIdx++})`);
        params.push(levels);
      }

      const where = conditions.join(" AND ");
      const { rows } = await pool.query(
        `SELECT id, tier, front as question, options, correct_answer, rationale_correct as rationale,
                distractor_rationales, clinical_takeaway, exam_pearl,
                rationale_media, lesson_links, body_system as category,
                topic, subtopic, difficulty, question_type, region_scope
         FROM flashcard_bank WHERE ${where}
         ORDER BY RANDOM() LIMIT $${paramIdx}`,
        [...params, count]
      );

      function safeParseJson(val: any, fallback: any = []) {
        if (val === null || val === undefined) return fallback;
        if (typeof val === "object") return val;
        try { return JSON.parse(val); } catch { return fallback; }
      }

      const mapped = rows.map((r: any) => {
        let opts = safeParseJson(r.options, []);
        if (!Array.isArray(opts)) opts = [];
        const correctIdx = safeParseJson(r.correct_answer, []);
        const idx = Array.isArray(correctIdx) ? correctIdx[0] : correctIdx;
        const optTexts = opts.map((o: any) => typeof o === "object" ? (o.text || String(o)) : String(o));
        const letters = ["A", "B", "C", "D", "E", "F"];
        const correctLetter = letters[idx] || "A";

        const distractors = safeParseJson(r.distractor_rationales, {});
        const media = safeParseJson(r.rationale_media, []);
        const lessons = safeParseJson(r.lesson_links, []);

        return {
          id: r.id,
          question: r.question,
          optionA: optTexts[0] || "",
          optionB: optTexts[1] || "",
          optionC: optTexts[2] || "",
          optionD: optTexts[3] || "",
          correctAnswer: correctLetter,
          rationale: r.rationale || "",
          category: r.category || "General",
          difficulty: r.difficulty <= 2 ? "easy" : r.difficulty === 3 ? "moderate" : r.difficulty === 4 ? "hard" : "very_hard",
          topic: r.topic || "",
          clientNeeds: "",
          examType: r.tier,
          country: r.region_scope || "BOTH",
          questionType: r.question_type || "mcq",
          clinicalTakeaway: r.clinical_takeaway || "",
          examPearl: r.exam_pearl || "",
          distractorRationales: distractors,
          rationaleMedia: media,
          lessonLinks: lessons,
        };
      });

      res.json(mapped);
    } catch (e: any) {
      console.error("[Test Bank Study]", e);
      res.status(500).json({ error: e.message });
    }
  });

